window.allTests = window.allTests || {};

window.allTests["klasik_u3_somurgeci_1"] = [
    {
        soru: "<i>\"Osmanlıların İpek ve Baharat Yolları üzerindeki denetimi, Avrupalı tüccarların Doğu ile ticaret yapabilmesini güçleştirmiştir. Venedik ve Cenevizli tüccarlar, Osmanlı gümrük vergilerini ödeyerek bu ticareti sürdürmeye devam etmiş; ancak Portekiz ve İspanya gibi Atlantik kıyısındaki devletler, doğrudan deniz yolu arayışına yönelmiştir.\"</i> [cite: 185]<br><br><b>Bu metni esas alarak Avrupalı devletlerin coğrafi keşiflere yönelmesinde Osmanlı İmparatorluğu'nun ticaret politikasının rolünü değerlendiriniz. Ayrıca Venedik ile Portekiz arasındaki farklı tepkilerin arkasında yatan mantığı açıklayınız.</b>",
        cevap: "Osmanlı'nın İpek ve Baharat Yolları üzerindeki hakimiyeti, Avrupalı tüccarların maliyetlerini artırmıştır[cite: 262]. Venedik gibi Akdeniz devletleri yerleşik ticaret ilişkileri sayesinde bu maliyetlere katlanabilirken; Portekiz ve İspanya gibi Atlantik kıyısındaki devletler Doğu ile doğrudan bağlantı kurmak için alternatif deniz yolları arayışına girmiştir[cite: 262]. Venedik 'aracı tüccar' konumunu sürdürebilmeyi gözetirken, Portekiz ve İspanya bu sistemi devre dışı bırakmayı tercih etmiştir[cite: 262]."
    },
    {
        soru: "<i>\"XV. yüzyılın sonlarında Akdeniz, hâlâ Avrupa ticaretinin kalbiydi; Lizbon, Barselona ve Marsilya birbiriyle rekabet eden liman şehirleriydi. Ümit Burnu'nun keşfinin ardından geçen bir nesil içinde bu dengeyi altüst eden kuvvetler harekete geçti: Atlantik kıyısı limanları yükselirken Doğu Akdeniz limanları sessizce büyük ticaret hacimlerini yitirmeye başladı.\"</i> [cite: 189]<br><br><b>Braudel'in bu tespitinden hareketle coğrafi keşiflerin Akdeniz ticaret düzenini nasıl dönüştürdüğünü açıklayınız. Bu dönüşümün Osmanlı İmparatorluğu için ekonomik sonuçlarını belirtiniz.</b>",
        cevap: "Ümit Burnu'nun keşfiyle Portekizliler, Hint Okyanusu baharat ticaretine Akdeniz'i devre dışı bırakarak ulaşmaya başlamış, bu durum İskenderiye, Venedik ve Halep gibi Akdeniz limanlarının ticaret hacmini önemli ölçüde azaltmıştır[cite: 264]. Osmanlı Devleti için bu dönüşüm; İpek ve Baharat Yollarından elde edilen gümrük gelirlerinin düşmesine ve Akdeniz'in stratejik öneminin azalmasıyla denizaşırı güçlere karşı dengeleme kapasitesinin zayıflamasına neden olmuştur[cite: 264]."
    },
    {
        soru: "<i>\"Vasco da Gama'nın 1498'de Kalküta'ya ulaşması, Portekizlilere Hint Okyanusu'nda savaşa hazır bir deniz filosu kurma fırsatı verdi. Bu filo, geleneksel Müslüman tüccarların ve Osmanlı'nın nüfuz alanını doğrudan tehdit etmekte; baharat ticaretini kontrol altına alma yarışında Osmanlı ile Portekiz arasında gizli bir mücadeleyi başlatmaktaydı.\"</i> [cite: 192]<br><br><b>Bu metne dayanarak Portekiz'in Hint Okyanusu'na girişinin neden yalnızca ticari değil, aynı zamanda jeopolitik bir meydan okuma olduğunu açıklayınız. Osmanlı'nın bu tehdide karşı nasıl bir tutum sergilediğini tartışınız.</b>",
        cevap: "Portekiz'in Hint Okyanusu'na girmesi, Osmanlı'nın Müslüman dünyası üzerindeki ticari ve dinî otoritesini zedeleme potansiyeli taşıyan bir jeopolitik hamledir[cite: 266]. Osmanlı bu tehdide; Hint Okyanusu'na donanma gönderme (Piri Reis, Seydi Ali Reis gibi denizcilerle), yerel Müslüman ticaret ağlarını destekleme ve Hürmüz ile Aden gibi stratejik limanları kontrol altında tutma girişimleriyle karşılık vermiştir[cite: 266]."
    },
    {
        soru: "<i>\"XVI. yüzyılın ikinci yarısından itibaren Amerika'dan Avrupa'ya akan büyük miktardaki gümüş, kıtada ciddi bir fiyat artışını tetikledi. Bu 'Fiyat Devrimi' dalgası zamanla Osmanlı topraklarına da ulaştı; gümüşün satın alma gücü düştükçe Osmanlı hazinesinin sabit vergi gelirleri reel değerini yitirdi ve devlet maliyesi üzerinde kronik bir baskı oluştu.\"</i> [cite: 196]<br><br><b>Bu metinden hareketle 'Fiyat Devrimi'nin Osmanlı maliyesi üzerindeki etkilerini açıklayınız. Bu etkinin yalnızca dışsal bir faktör mü, yoksa Osmanlı'nın iç yapısal sorunlarının bir parçası mı olduğunu tartışınız.</b>",
        cevap: "Amerika'dan akan gümüş para arzını artırarak fiyatları yükseltmiştir[cite: 268]. Osmanlı vergi sistemi sabit gümüş akçesi üzerinden belirlendiğinden, hazinenin reel alım gücü düşmüş ve bu durum tımar sisteminin çöküşünü hızlandırarak iltizam sistemine geçişi zorunlu kılmıştır[cite: 268]. Bu kriz salt dışsal bir şok olmayıp, askeri harcamaların artması ve merkezi otoritenin zayıflaması gibi iç yapısal sorunlarla birleşerek derinleşmiştir[cite: 268]."
    },
    {
        soru: "<i>\"Portekizliler, Hindistan yolunu yalnızca ticari çıkar için değil, haçlı zihniyetiyle de buldular: İspanya'nın Reconquista ruhunu Atlantik'in ötesine taşımak, Müslüman ticaret ağlarını kuşatmak ve İslam'a karşı kutsal bir ittifak kurmak amacıyla ilerliyorlardı. Bu nedenle Portekiz seferleri kılıç ve ticaret gemisini daima yan yana götürdü.\"</i> [cite: 200]<br><br><b>Bu metni ve konunun bağlamını dikkate alarak Portekizlilerin sömürgeci faaliyetlerinde dinî motifler ile ekonomik çıkarların nasıl iç içe geçtiğini analiz ediniz. Bu iki güdünün zaman içinde nasıl bir denge kurduğunu tartışınız.</b>",
        cevap: "Portekiz sömürgeciliği, Müslümanlara karşı kutsal savaş ve Hristiyanlığı yayma gibi dinî motivasyonları, baharat ve altın ticaretini ele geçirme gibi ekonomik hedeflerle birleştirmiştir[cite: 270]. Dinî söylem sömürgeciliği meşru kılıp devlet desteğini kolaylaştırırken, zamanla ekonomik çıkarlar daha ağır basmış ve dinî motifler araçsallaşmıştır[cite: 270]."
    },
    {
        soru: "<i>\"Hollanda Doğu Hindistan Şirketi (VOC), özel ticaret anlayışını ve devlet desteğini birleştirerek Portekiz'in kurduğu sistemden çok daha etkin bir ticaret imparatorluğu inşa etti. VOC, Asya'daki taşıma fiyatlarını dramatik biçimde düşürerek Osmanlı topraklarından geçen kara yolunu kullanılamaz hâle getirdi.\"</i> [cite: 204]<br><br><b>Bu alıntıdan hareketle Hollanda'nın Portekiz'in yerini almasındaki temel nedenleri tartışınız. Bu süreçte Osmanlı İmparatorluğu'nun ticaret gelirlerine yönelik etkiyi değerlendiriniz.</b>",
        cevap: "Hollanda'nın üstünlüğü; düşük maliyetli Fluyt gemileri, riski dağıtan ortak sermayeli VOC yapısı ve Asya'da kurulan kalıcı ticaret üslerine dayanmaktadır[cite: 272]. Bu süreç, Osmanlı üzerinden geçen kara yolu ticaret gelirlerinin Portekiz dönemine kıyasla çok daha kalıcı ve yıkıcı biçimde çökmesine neden olmuştur[cite: 272]."
    },
    {
        soru: "<i>\"Osmanlı devleti, ticaret dengesini korumak ve yabancı tüccarları çekmek amacıyla çeşitli Avrupa devletlerine kapitülasyon adı verilen ticari ayrıcalıklar tanıdı. Bu ayrıcalıklar başlangıçta karşılıklılık ilkesine dayanmakta ve Osmanlı'nın ekonomik stratejisinin ayrılmaz bir parçasını oluşturmaktaydı.\"</i> [cite: 207]<br><br><b>Kapitülasyonların Osmanlı Devleti açısından başlangıçtaki mantığını açıklayınız. Bu ayrıcalıkların zamanla nasıl bir dönüşüm geçirdiğini ve Osmanlı ekonomisi üzerindeki uzun vadeli etkilerini değerlendiriniz.</b>",
        cevap: "Başlangıçta kapitülasyonlar, Bizans sonrası boşalan ticaret ağlarını canlandırmak ve Avrupa ile ticareti sürdürerek gümrük gelirlerini artırmak için diplomatik bir araç olarak kullanılmıştır[cite: 274]. Ancak 17. yüzyıldan itibaren güç dengesi değiştikçe bu ayrıcalıklar genişlemiş; Osmanlı'nın yerli üretimini baskı altına alarak imparatorluğu hammadde ihraç eden asimetrik bir ekonomik ilişkiye hapsetmiştir[cite: 274]."
    },
    {
        soru: "<i>\"Osmanlı arşiv belgeleri, 1550-1600 yılları arasında tahıl ve tekstil fiyatlarının ikiye, hatta üçe katlandığını ortaya koymaktadır. Bu fiyat hareketi, yalnızca paranın değer kaybıyla açıklanamaz; aynı zamanda talep artışı, nüfus büyümesi ve arzın kıtlığı gibi iç dinamikler de bu süreci beslemiştir.\"</i> [cite: 210]<br><br><b>Barkan'ın tespitinden hareketle Osmanlı'daki fiyat artışının çok etkenli bir süreç olduğunu ortaya koyunuz. Dışsal etkenler (Fiyat Devrimi) ile iç dinamikler arasındaki ilişkiyi nasıl değerlendirirsiniz?</b>",
        cevap: "Fiyat artışları hem dışsal (Amerika'dan gelen gümüşün yarattığı para değer kaybı) hem de içsel (hızlı nüfus artışı sonucu gıda talebinin arzı aşması ve uzun süreli savaşların maliyeti) etkenlerin birleşimidir[cite: 276]. Bu çok etkenli yapı birbirini pekiştirerek krizin etkisini artırmıştır[cite: 276]."
    },
    {
        soru: "<i>\"XVI. yüzyılda Akdeniz, yalnızca bir ticaret havzası değil, iki dünya görüşü arasındaki bir sınır bölgesiydi. Osmanlı ve İspanya bu denizde askeri olduğu kadar ideolojik bir hegemonya mücadelesi sürdürdü. Her iki güç de denizin kontrolünü yalnızca ticaret için değil, meşruiyet ve simgesel egemenlik için de arzu ediyordu.\"</i> [cite: 214]<br><br><b>Bu metni esas alarak 16. yüzyılda Osmanlı-İspanya rekabetinin salt askeri bir çatışmanın ötesine geçtiğini nasıl açıklarsınız? Bu rekabet Avrupalı sömürgecilik süreciyle nasıl ilişkilendirilebilir?</b>",
        cevap: "Bu rekabet, İspanya'nın 'Haçlı gücü' kimliği ile Osmanlı'nın 'İslam'ın koruyucusu' unvanı arasındaki ideolojik ve simgesel bir çatışmadır[cite: 278]. Sömürgecilikle ilişkisi ise, Osmanlı'nın bu sürece doğrudan katılmak yerine Akdeniz hakimiyeti ve Müslüman ticaret ağlarını koruyarak sömürgeci genişlemeyi dengelemeye çalışmasıdır[cite: 278]."
    },
    {
        soru: "<i>\"Avrupalı fatihlerin en güçlü silahı gemileri ya da barut silahları değildi; yanlarında taşıdıkları çiçek, kızamık ve tifüs gibi bulacı hastalıklardı. Amerika yerlilerinin bu hastalıklara karşı hiçbir bağışıklığı yoktu ve kimi bölgelerde nüfusun yüzde doksanı kısa sürede yok oldu.\"</i> [cite: 218]<br><br><b>Bu metinden hareketle Avrupa'nın sömürgeci başarısında biyolojik faktörlerin rolünü değerlendiriniz. Yalnızca askeri ve teknolojik üstünlüğe odaklanan sömürgecilik analizlerinin bu boyutu ne ölçüde göz ardı ettiğini tartışınız.</b>",
        cevap: "Avrupalıların sömürgeci başarısı salt silah gücüne değil, bağışıklığı olmayan yerli nüfusları fetih öncesinde çökerten salgın hastalıklara dayanmaktadır[cite: 280]. Bu biyolojik faktör, askeri ve teknolojik üstünlüğün etkisini katlayan bir unsurdur[cite: 280]. Osmanlı coğrafyasında ise bu biyolojik avantaj oluşmadığı için Avrupalı ilerleyişi sadece ticari ve askeri yarışla sınırlı kalmıştır[cite: 280]."
    },
    {
        soru: "<i>\"Atlantik köle ticareti, yalnızca ekonomik bir olgu olmayıp sömürge ekonomisinin temelini oluşturuyordu. Şeker, tütün ve pamuk gibi tropik ürünlerin büyük çiftliklerde işlenmesi, zorla getirilen Afrika nüfusu olmaksızın hayal bile edilemezdi. Bu ekonomik sistem, aynı zamanda 'ırk' kavramının modern anlamda inşasının da temelidir.\"</i> [cite: 222]<br><br><b>Bu metni ve konuyu dikkate alarak Atlantik köle ticaretinin sömürge ekonomisiyle nasıl bütünleştiğini açıklayınız. Bu sürecin Osmanlı İmparatorluğu'ndaki kölelik anlayışından farkını değerlendiriniz.</b>",
        cevap: "Atlantik köle ticareti, plantation ekonomisinin (şeker, pamuk vb.) ihtiyaç duyduğu yoğun ve ucuz emeği sağlayarak sermaye birikiminin motoru olmuştur[cite: 282]. Osmanlı'daki kölelikten farkı; Osmanlı'da köleliğin ırka dayalı kalıtsal bir statü olmaması, kölelerin toplumsal yükselme ve özgürleşme imkânının bulunmasıdır; oysa Atlantik sisteminde kölelik kalıtsal ve ırksal bir hiyerarşiye dayanır[cite: 282]."
    },
    {
        soru: "<i>\"XVI. yüzyılda oluşan kapitalist dünya ekonomisi, Batı Avrupa'yı merkeze, Doğu Avrupa ile Amerika'yı çevreye ve bazı bölgeleri 'yarı çevre'ye yerleştirdi. Osmanlı İmparatorluğu bu dönemde merkezi piyasa ilişkilerinin dışında kalmayı başardıysa da uzun vadede sistemin dış baskılarına dayanma kapasitesi giderek zayıfladı.\"</i> [cite: 226]<br><br><b>Wallerstein'ın 'dünya sistemi teorisi'ni esas alarak Osmanlı'nın 16-17. yüzyıldaki ekonomik konumunu değerlendiriniz. Bu teorinin Osmanlı tarihine uygulanmasının hangi güçlükleri barındırdığını da tartışınız.</b>",
        cevap: "Wallerstein'a göre Osmanlı başlangıçta sistemin dışındaydı ancak 17. yüzyıldan itibaren kapitülasyonlar yoluyla hammadde sağlayan bir 'çevre' konumuna sürüklenmiştir[cite: 284]. Teorinin güçlüğü, Osmanlı'yı dışsal güçlerce şekillendirilen pasif bir özne olarak görmesi ve devletin aktif direnişini ve iç ticaret politikasını ihmal etmesidir[cite: 284]."
    },
    {
        soru: "<i>\"Hint Okyanusu, Portekizlilerin gelişinden önce, Arap, Hint, Çin ve Osmanlı tüccarlarının ortak kullandığı çok merkezli bir ticaret havzasıydı. Portekizliler bu düzene kendi askeri şiddet tekellerini dayatarak girdiler; ne var ki mevcut ticaret ağlarını tamamen yok edemediler, yalnızca üstüne yapışıp onları yeniden biçimlendirdiler.\"</i> [cite: 230]<br><br><b>Bu metinden yola çıkarak Portekizlilerin Hint Okyanusu'nda kurduğu düzenin, eski ticaret sisteminin tamamen yıkılmasından mı yoksa onunla bütünleşmesinden mi ibaret olduğunu tartışınız. Osmanlı'nın bu sistemdeki konumunu belirtiniz.</b>",
        cevap: "Portekiz hakimiyeti mutlak bir yıkım değil, mevcut ağlar üzerinde kurulan bir askeri hegemonyadır; tüccarlar Kartaz sistemiyle denetim altına alınmaya çalışılmıştır[cite: 286]. Osmanlı, Kızıldeniz ve Basra Körfezi üzerinden geleneksel Müslüman ticaret ağlarını korumaya çalışmış ve Portekiz ablukasını kırmak için Hint seferleri düzenleyerek sisteme direnmiştir[cite: 286]."
    },
    {
        soru: "<i>\"Piri Reis yalnızca bir denizci değil, Osmanlı devletinin Hint Okyanusu'na açılma stratejisinin sembolüydü. Onun haritaları, Osmanlı'nın coğrafi bilgi birikiminin ne denli ileri bir düzeye ulaştığını göstermektedir. Buna karşın bu bilgi birikimi, kalıcı bir denizaşırı strateji oluşturmak için yeterli politik ve lojistik altyapıya kavuşturulamamıştır.\"</i> [cite: 234]<br><br><b>Bu metinden hareketle Osmanlı'nın Hint Okyanusu'nda kalıcı bir deniz gücü hâline gelemeyişinin arkasındaki nedenleri tartışınız. Coğrafi bilgi birikiminin tek başına stratejik kapasiteye dönüşmesinin neden yeterli olmadığını açıklayınız.</b>",
        cevap: "Kalıcı güç olunamamasının nedenleri; Akdeniz kadırgalarının okyanus koşullarına uygun olmaması, Habsburg ve Safevi savaşlarının yarattığı çok cepheli baskı ve merkezin kara seferlerine öncelik vermesidir[cite: 288]. Coğrafi bilgi, onu destekleyecek lojistik altyapı ve politik odaklanma olmadıkça tek başına stratejik üstünlük sağlamaya yetmemiştir[cite: 288]."
    },
    {
        soru: "<i>\"Sömürgeciliğin en kalıcı mirası, toprak ya da kaynak ele geçirmenin çok ötesinde, sosyal ve kültürel alanda ortaya çıktı. Avrupalıların sömürge topluluklarına taşıdığı dil, hukuk anlayışı, tarım teknikleri ve hastalıklar, sömürgeleştirilmiş halkların yapısını köklü biçimde değiştirdi.\"</i> [cite: 238]<br><br><b>Bu metni esas alarak Avrupalı sömürgeciliğin ekonomik boyutunun ötesinde uzanan sosyal ve kültürel etkilerini tartışınız. Bu etkilerin dönemin Osmanlı toplumu ve yönetimi üzerinde doğrudan bir yansıması olup olmadığını değerlendiriniz.</b>",
        cevap: "Sömürgecilik dil, hukuk ve inanç sistemlerini taşıyarak toplumsal yapıları dönüştürmüş; 'kültürel hibridleşme'ye yol açmıştır[cite: 290]. Osmanlı doğrudan sömürgeleştirilmediği için bu etki dolaylı olmuştur; örneğin Amerika kökenli bitkilerin (patates, tütün vb.) mutfağı ve tarımı değiştirmesi veya liman kentlerinde Avrupalı tüccarların yarattığı yeni sosyal dinamikler bu yansımalardandır[cite: 290]."
    }
];
window.allTests = window.allTests || {};

window.allTests["klasik_u3_somurgeci_2"] = [
    {
        soru: "<i>\"Merkantilist devlet, ihracatı teşvik edip ithalatı kısıtlayarak ülkeye sürekli değerli maden akışını sağlamayı amaçlıyordu. Bu anlayış gereği sömürgeler, anavatanın hammadde deposu ve pazar alanı olarak tasarlandı; sömürge halkının kendi üretim kapasitesi ise kasıtlı biçimde baskı altında tutuldu.\"</i> [cite: 242]<br><br><b>Merkantilist anlayışın sömürge politikasını nasıl şekillendirdiğini açıklayınız. Bu politikanın Osmanlı'nın Avrupalı devletlerle olan ekonomik ilişkilerine yansımalarını değerlendiriniz.</b>",
        cevap: "Merkantilizm, sömürgeleri hammadde kaynağı ve mamul mal alıcısı olarak konumlandırarak sanayileşmelerini engellemiş ve kalıcı bir bağımlılık yaratmıştır[cite: 292]. Osmanlı'ya yansıması ise kapitülasyonlar aracılığıyla Avrupalıların pazara girmesiyle olmuş; Osmanlı zamanla hammadde ihraç eden, mamul mal ithal eden 'yarı sömürge' ekonomi görünümüne sürüklenmiştir[cite: 292]."
    },
    {
        soru: "<i>\"Osmanlı fethi, Balkanlar'da salt bir askeri gelişme değildi; uzun vadeli demografik, ekonomik ve kültürel dönüşümleri de beraberinde getirdi. İstimalet politikası sayesinde bazı bölgeler Osmanlı döneminde öncekinden daha müreffeh bir çehre kazandı; bu durum, Avrupa merkezli sömürgecilik anlatılarının öngördüğü tek boyutlu 'yağma' söylemini sorgulatmaktadır.\"</i> [cite: 245]<br><br><b>Malcolm'un bu tespitinden hareketle Osmanlı yönetiminin 'sömürge' olarak nitelendirilemeyeceğini ya da bu nitelendirmenin sorunlarını tartışınız. Osmanlı genişlemesini Avrupalı sömürgeciliğiyle karşılaştırdığınızda ne gibi temel farklılıklar öne çıkar?</b>",
        cevap: "Osmanlı yönetimi, yerli halkı sürmek yerine istimalet ve millet sistemiyle entegre ettiği, yerel dini/hukuki yapıları koruduğu ve hammadde sömürüsüne dayalı tek yönlü kapitalist bir ilişki kurmadığı için klasik Avrupa sömürgeciliğinden ayrılır[cite: 294]. Temel fark, sömürgeciliğin ırka ve kapitalist sömürüye dayalı yapısının Osmanlı sisteminde karşılığının bulunmamasıdır[cite: 294]."
    },
    {
        soru: "<i>İnalcık: \"Osmanlı'nın Doğu ticaret yollarını kontrol altında tutması, başlı başına bir ekonomik strateji olarak Osmanlı gücünün maddi zeminini oluşturmuş; bu stratejinin çöküşü Osmanlı İmparatorluğu'nun yapısal krizinin de başlangıcı sayılabilir.\"<br>Pamuk: \"Osmanlı ekonomik krizinin temelinde ticaret yollarının kaymasından çok, para politikasındaki tutarsızlıklar ve akçenin sistematik tağşişi yatmaktadır...\"</i> [cite: 249]<br><br><b>İnalcık ve Pamuk'un Osmanlı ekonomik krizine ilişkin yaklaşımlarını karşılaştırarak her iki yorumun güçlü ve zayıf yönlerini tartışınız. Hangi yorumun daha bütünlüklü bir açıklama sunduğunu gerekçeleriyle savununuz.</b>",
        cevap: "İnalcık ticaret yollarının kaybının stratejik ve mali zayıflama yarattığını (yapısal kırılma) savunurken, Pamuk para arzı ve tağşiş politikasını (parasal kriz) ön plana çıkarır[cite: 296]. Bütünlüklü açıklama, ticaret yollarının kaymasının yarattığı uzun vadeli zayıflığın, para politikası hatalarıyla birleşerek krizi derinleştirdiğini kabul eden sentez yaklaşımdır[cite: 296]."
    },
    {
        soru: "<i>Braudel: \"Akdeniz, XVI. yüzyılın ikinci yarısında Osmanlı ile İspanya arasında ikiye bölünmüş; her iki güç de denizi yönetmekten çok, kıyıları denetlemeye razı olmuştu.\"<br>Özbaran: \"Osmanlı'nın Kızıldeniz ve Hürmüz üzerindeki stratejik çıkarları, pasif bir tutumu değil, aktif bir güney politikasını zorunlu kılıyordu...\"</i> [cite: 253]<br><br><b>Braudel ve Özbaran'ın bakış açılarını karşılaştırınız. Osmanlı'nın 16. yüzyıldaki deniz politikasını 'pasif savunma' mı yoksa 'aktif yayılma' olarak mı nitelendirmek daha isabetlidir? Her iki tarihçinin metodolojik tercihlerinin bu değerlendirmeyi nasıl etkilediğini açıklayınız.</b>",
        cevap: "Braudel Akdeniz odağıyla Osmanlı'yı İspanya karşısında pasif-savunmacı görürken, Özbaran güney arşivlerine dayanarak Hint Okyanusu'nda aktif bir yayılma stratejisi olduğunu gösterir[cite: 298]. Osmanlı'nın aslında Akdeniz'de savunmacı, güneyde ise aktif-yayılmacı bir ikili strateji izlediği söylenebilir[cite: 298]. Metodolojik fark, coğrafi odak ve kullanılan kaynak tabanından kaynaklanmaktadır[cite: 298]."
    },
    {
        soru: "<i>Kafadar: \"Osmanlı Devleti'nin yükselişini ve gerilemesini tek bir nedenle açıklamak tarihsel gerçeklikle bağdaşmaz...\"<br>Murphey: \"XVI. yüzyılın sonunda Osmanlı ordusunun ateşli silahlara hızla uyum sağladığı görülmekte; bu durum 'Osmanlı gerilemesi' tezinin basit versiyonlarını ciddi biçimde sorgulatmaktadır.\"</i> [cite: 257]<br><br><b>Kafadar ve Murphey'in bu tespitleri ışığında 'Osmanlı gerilemesi' tezini eleştirel bir gözle değerlendiriniz. Avrupalı sömürgeciliğin yükselişini Osmanlı'nın kaçınılmaz çöküşüyle ilişkilendiriren tarih yazımının hangi metodolojik sorunları barındırdığını açıklayınız.</b>",
        cevap: "'Osmanlı gerilemesi' tezi, devletin adaptasyon kapasitesini göz ardı eden ideolojik bir kurgudur[cite: 300]. Metodolojik sorunlar; 'gerileme'yi kaçınılmaz gören teleolojik yanılgı ve Osmanlıyı 'geri' konumlandıran Batı merkezciliktir[cite: 300]. Sömürgeciliğin yükselişi ile Osmanlı'nın durumunu doğrudan neden-sonuç ilişkisine bağlamak, iki ayrı sürecin iç dinamiklerini basitleştirme hatasına düşmektedir[cite: 300]."
    },
    {
        soru: "<i>\"XV. yüzyılın sonunda Osmanlı İmparatorluğu, Doğu Akdeniz'i büyük ölçüde kontrol altında tutuyordu. Bu hakimiyet, Avrupa'nın Doğu ile ticaret yapmasını zorlaştırıyor; baharat, ipek ve değerli kumaşların fiyatlarını sürekli yüksek tutuyordu. Avrupalı tüccarların maliyetlerini düşürmek için alternatif yol arayışına girmeleri kaçınılmaz hâle gelmişti.\"</i> [cite: 359]<br><br><b>Bu metinden hareketle Osmanlı'nın ticaret yolları üzerindeki hakimiyetinin Avrupa'yı deniz yolları keşfine iten bir etken olup olmadığını tartışınız. Bu bağlamda Osmanlı'nın rolünü belirleyici mi, kolaylaştırıcı mı yoksa sınırlı bir etken olarak mı değerlendirirsiniz?</b>",
        cevap: "Osmanlı hakimiyeti keşifleri tetikleyen tek neden değil; Rönesans merakı, gemicilik teknolojisi ve maden arayışı gibi etkenlerle birleşen 'kolaylaştırıcı-motive edici' bir unsurdur[cite: 437]. Tek belirleyici (tek neden) saymak tarihsel gerçekliği basitleştirmek olur; ancak maliyet artışı yoluyla Avrupalıları denizlere iten önemli bir faktördür[cite: 437]."
    },
    {
        soru: "<i>\"Coğrafi Keşifler'in ardından Atlantik ticaret merkezlerinin yükselişi, Osmanlı'nın elinde bulundurduğu Akdeniz liman şehirlerinin ticaret hacmini büyük ölçüde düşürdü. Halep, İskenderiye ve Bursa gibi kentlerin uluslararası ticaret hayatındaki ağırlığı giderek azaldı; buna karşın bu şehirler iç ticaret açısından önemini korumaya devam etti.\"</i> [cite: 363]<br><br><b>Bu metinden yola çıkarak coğrafi keşiflerin Osmanlı liman şehirleri üzerindeki etkisini analiz ediniz. Uluslararası ticaretle iç ticaretin farklı biçimde etkilenmesini nasıl açıklarsınız?</b>",
        cevap: "Ümit Burnu güzergahı Akdeniz transit ticaretini doğrudan vurarak uluslararası hacmi düşürmüştür[cite: 439]. Ancak yerel tarım ve zanaat mamullerine dayanan iç ticaret, uluslararası baharat güzergahındaki değişimden daha az etkilenmiş ve şehirlerin yerel ekonomik işlevi sayesinde canlılığını korumuştur[cite: 439]."
    },
    {
        soru: "<i>\"Avrupa'nın sömürgeci genişlemesinde teknoloji belirleyici bir rol oynadı. Okyanuslara dayanıklı yelkenli gemiler, üstün top teknolojisi ve gelişmiş harita yapımcılığı, Avrupalılara Asya ve Amerika'nın yerli güçlerine karşı kalıcı bir üstünlük sağladı.\"</i> [cite: 367]<br><br><b>Teknolojik üstünlüğün sömürgeci genişlemedeki rolünü bu metin ışığında değerlendiriniz. Osmanlı'nın bu teknolojik dönüşüme verdiği yanıtı ve Avrupalılarla arasındaki farkı tartışınız.</b>",
        cevap: "Karavel gemileri, top teknolojisi ve ölçekli haritalama Avrupalılara okyanuslarda üstünlük sağlamıştır[cite: 441]. Osmanlı ateşli silahları (top, tüfek) hızla benimsemiş ancak denizcilikte Akdeniz tipi kadırga teknolojisini sürdürdüğü için okyanus koşullarına uyumda gecikmeli ve eksik kalmıştır[cite: 441]."
    },
    {
        soru: "<i>\"XVI. yüzyılın sonlarında Osmanlı taşrasında artan vergi yükleri, dirlik sahipleri ile köylüler arasındaki gerilimi tırmandırdı. Bu dönemde görülen Celali İsyanları, ekonomik sıkışmanın yarattığı toplumsal patlamanın en açık işaretiydi; ve bu sıkışmanın arkasında hem iç hem de dış dinamikler yatmaktaydı.\"</i> [cite: 370]<br><br><b>Bu metni ve dönemi göz önünde bulundurarak Avrupalı sömürgeciliğin yarattığı dışsal baskıların (ticaret yollarının kayması, Fiyat Devrimi) Osmanlı taşrasındaki toplumsal çalkantılarla nasıl bağlantılandırılabileceğini tartışınız.</b>",
        cevap: "Dışsal baskılar (Fiyat Devrimi ve ticaret kaybı) hazineyi zorlamış, devlet buna karşılık vergi yükünü artırmıştır[cite: 443]. Tımarın çöküp iltizamın gelmesiyle artan ağır ve keyfi sömürü, ekonomik kriz ve güvensizlikle birleşerek Celali İsyanlarının toplumsal patlamasına yol açmıştır[cite: 443]."
    },
    {
        soru: "<i>\"İspanyolların Yeni Dünya'dan getirdiği altın ve gümüş, başlangıçta İspanya'yı rakipsiz bir güç hâline getirdiyse de uzun vadede bu zenginlik, olumlu bir ekonomik dönüşüm yerine enflasyon ve kurumsal çürümeye yol açtı. 'Zenginliğin laneti' olarak bilinen bu paradoks, 16. yüzyılın sonunda İspanya'nın iflasını hazırladı.\"</i> [cite: 373]<br><br><b>Bu metinden hareketle sömürgeci zenginliğin bir devlet için her zaman kalıcı bir güç kaynağı olup olmayacağını tartışınız. İspanya'nın bu deneyimini Osmanlı'nın benzer bir 'beklenmedik gelir' sorunuyla karşılaştırınız.</b>",
        cevap: "Sömürgeci zenginlik üretime yatırılmadığında enflasyona ve kurumsal çürümeye yol açan bir 'lanete' dönüşebilir[cite: 445]. İspanya gümüşle enflasyon yaşarken, Osmanlı da fetih ve haraç gelirleri azaldığında mevcut tımar sistemini sürdürememiş ve her iki güç de ani zenginliği kalıcı reforma dönüştüremediği için yapısal kırılganlık yaşamıştır[cite: 445]."
    },
    {
        soru: "<i>\"Müslüman dünyası, Avrupa'nın sömürgeci genişlemesinin başlangıç döneminde bu tehdidin farkında bile değildi; çünkü Doğu kültürü bu dönemde kendini üstün, Batı'yı ise geri ve önemsiz görmekteydi.\"</i> [cite: 377]<br><br><b>Bu metni eleştirel bir bakış açısıyla okuyunuz. Lewis'in tezinin hangi noktaları haklı bulunabilir, hangi noktaları ise tarihsel gerçekliği basitleştiriyor olabilir? Osmanlı'nın Avrupalı gelişmelere verdiği somut tepkilerle yanıtlayınız.</b>",
        cevap: "Lewis'in Batı'nın teknolojik ve kurumsal üstünlüğünün gecikmeli fark edildiği tezi haklı yönler barındırsa da, 'farkında değildi' iddiası 16. yüzyıldaki Hint seferleri ve Portekiz'e karşı kurulan diplomatik ittifaklar gibi somut Osmanlı tepkilerini yok saydığı için basitleştiricidir[cite: 447]."
    },
    {
        soru: "<i>\"Osmanlı, Akdeniz'de salt askeri güç değil, aynı zamanda ticaret aracı olarak diplomasiyi de etkin biçimde kullandı. Fransa ile 1536'da imzalanan kapitülasyon anlaşması; Osmanlı'nın Avrupalı devletler arasındaki rekabeti kendi çıkarları doğrultusunda kullanma kapasitesini gözler önüne serdi.\"</i> [cite: 381]<br><br><b>Bu metinden hareketle Osmanlı'nın Avrupalı sömürgecilik döneminde izlediği diplomatik stratejileri değerlendiriniz. Bu stratejilerin Osmanlı'ya ne gibi kazanımlar sağladığını ve ne gibi uzun vadeli maliyetlere yol açtığını tartışınız.</b>",
        cevap: "Osmanlı, Fransa ittifakıyla Habsburgları dengelemiş ve kapitülasyonlarla ticari canlılığı korumuştur[cite: 449]. Kazanım kısa vadeli diplomatik ve mali başarı iken; uzun vadeli maliyet, bu imtiyazların zamanla genişleyerek Osmanlı'yı asimetrik ekonomik ilişkilere ve zafiyete açık hale getirmesidir[cite: 449]."
    },
    {
        soru: "<i>\"Merkantilist politikayı benimseyen Avrupalı devletler, hammadde ve pazar arayışıyla Osmanlı gibi ülkeleri hedef haline getirirken aynı zamanda sürekli ayrıcalık talebiyle Osmanlı Devleti'ne baskı yapmaya başlamıştır.\"</i> [cite: 385]<br><br><b>Bu akademik tespiti esas alarak merkantilizmin Osmanlı'ya yönelik ekonomik ve siyasi baskı boyutlarını açıklayınız. Osmanlı'nın bu baskılara verdiği yanıtların yeterliliğini değerlendiriniz.</b>",
        cevap: "Merkantilist baskı, Osmanlı'yı hammadde ihraç edip mamul mal alan bir pazar yapmaya çalışmış; kapitülasyonlar bu asimetrinin yasal çerçevesi olmuştur[cite: 451]. Osmanlı'nın diplomatik yanıtları kısa vadede esneklik sağlasa da, tımar ve lonca yapısının katılığından dolayı uzun vadeli sanayileşme ve üretim dönüşümü gerçekleştirilememiştir[cite: 451]."
    },
    {
        soru: "<i>\"XVI. ve XVII. yüzyıllarda Osmanlı, Safevi, Hint Babür ve Çin Ming gibi büyük kara imparatorlukları, Avrupalı deniz güçlerinin yayılmasına karşı farklı düzeylerde direnç gösterdi. Bu 'büyük kara imparatorlukları' döneminin ortak özelliği, merkezi otoritenin denizaşırı ticaret yerine toprak kontrolüne dayalı bir güç anlayışına dayanmasıydı.\"</i> [cite: 389]<br><br><b>Bu karşılaştırmalı perspektiften hareketle Osmanlı'nın denizaşırı güçlere karşı kalıcı bir deniz stratejisi geliştiremeyişini yapısal bir sorun olarak mı yoksa bilinçli bir tercih olarak mı değerlendirirsiniz?</b>",
        cevap: "Bu durum hem yapısal bir kısıt (kara ordusuna ayrılan devasa kaynaklar, ticaret burjuvazisinin yokluğu) hem de rasyonel bir tercihtir (korsanları destekleme ve Akdeniz/iç deniz güvenliğini önceliklendirme)[cite: 453]. Osmanlı yapısal kapasite bakımından okyanus şirketleri kuran rakipleri kadar yatırım yapamamıştır[cite: 453]."
    },
    {
        soru: "<i>\"Osmanlı devleti, XVI. yüzyılın sonunda ciddi bir mali tıkanıklıkla yüzleşti. Fetih gelirlerinin azalması, askeri harcamaların artması ve para değerinin düşmesi, devletin mali yapısını kökünden sarstı.\"</i> [cite: 393]<br><br><b>Bu metni esas alarak Osmanlı'nın 16. yüzyıl sonundaki mali krizini yaratan etkenleri sistematik biçimde açıklayınız. Bu krizin çözümüne yönelik girişimlerin neden yetersiz kaldığını tartışınız.</b>",
        cevap: "Krizi yaratanlar; fetih durunca tımarın yetersiz kalması, uzun İran ve Avusturya savaşlarının maliyeti ve tağşişin yarattığı enflasyondur[cite: 455]. Çözüm girişimleri (iltizam, vergi artışı) üretimi artırmak yerine mevcut kaynakları yeniden dağıtmayı hedefleyen 'yama' çözümler olduğu için yetersiz kalmıştır[cite: 455]."
    }
];
window.allTests = window.allTests || {};

window.allTests["klasik_u3_somurgeci_3"] = [
    {
        soru: "<i>\"XVII. yüzyıl İngiltere'sinde gelişen sömürgeci düşünce, salt askeri fetih değil, ticari kolonizasyon olarak kendini tanımladı. Doğu Hindistan Şirketi gibi kurumlar, devlet desteğini özel sermayeyle birleştirerek sömürgeciliğini kurumsal bir düzene oturttu.\"</i> [cite: 397]<br><br><b>Bu metni esas alarak İngiliz sömürgeciliğinin diğer Avrupa güçlerinden (Portekiz, İspanya) neden farklı bir nitelik taşıdığını açıklayınız. Bu farklılığın Osmanlı ile İngiliz ticaret ilişkilerine yansımalarını değerlendiriniz.</b>",
        cevap: "İngiliz modeli, askeri fetih yerine özel sermayeyi örgütleyen anonim şirketler (East India Company) üzerinden ticari sömürgeciliği kurumsallaştırmıştır[cite: 457]. Osmanlı ile ilişkilerde Levant Company aracılığıyla hammadde-mamul mal takasına dayalı asimetrik bir ticaret yapısı kurarak Osmanlı üretimini baskı altına almıştır[cite: 457]."
    },
    {
        soru: "<i>\"Girit örneğinde görüldüğü üzere Osmanlı yönetimi altında Müslüman ve Hristiyan topluluklar, katı bir ayrışma yerine karmaşık bir ticari ve sosyal ortaklık içinde yaşadı. Bu çok dinli ticaret ortamı, Akdeniz ekonomisini Avrupalı sömürge ekonomisinden yapısal olarak ayıran temel özelliklerden birini oluşturmaktaydı.\"</i> [cite: 401]<br><br><b>Bu metinden hareketle Osmanlı Akdeniz'inin çoğulcu ticaret yapısını Avrupalı sömürge ekonomisiyle karşılaştırınız. Bu çoğulcu yapının Osmanlı'ya sağladığı avantajları ve uzun vadeli kırılganlıklarını değerlendiriniz.</b>",
        cevap: "Osmanlı sistemi farklı din ve etnisitelerin uzmanlıklarına dayanan esnek ve çoğulcu ağlar sunarken, Avrupa sömürge ekonomisi tek tip ve ırksal hiyerarşiye dayalıdır[cite: 459]. Avantajı ticaret ağlarının direncini artırmasıyken; kırılganlığı, devletin kontrol edemediği aracı ağlara bağımlılığı ve merkezi sermaye birikiminin zayıf kalmasıdır[cite: 459]."
    },
    {
        soru: "<i>\"Coğrafi keşiflerin ardından Amerika'dan Osmanlı topraklarına ulaşan yeni bitkiler (mısır, patates, domates, kahve çekirdeği) Osmanlı tarımını ve mutfak kültürünü derinden dönüştürdü. Bu bitkilerin kabulü, Osmanlı toplumunun küresel ekonomik değişimlere karşı pasif olmadığını; seçici uyum kapasitesine sahip olduğunu göstermektedir.\"</i> [cite: 405]<br><br><b>Bu metinden hareketle Osmanlı toplumunun coğrafi keşiflerin dolaylı sonuçlarına verdiği 'seçici uyum' tepkisini değerlendiriniz. Bu uyumun sınırlarını ve Osmanlı ekonomisi üzerindeki katkılarını tartışınız.</b>",
        cevap: "Mısır ve patates gibi verimli ürünlerin benimsenmesi gıda güvenliğini ve nüfus artışını desteklemiş; tütün ve kahve yeni ticaret alanları yaratmıştır[cite: 461]. Ancak bu 'seçici uyum' tarımsal düzeyde kalmış, sanayi veya ticaret altyapısında benzer bir dönüşüm tetiklememiş ve ticaret yollarının kayması sorununu çözememiştir[cite: 461]."
    },
    {
        soru: "<i>\"Portekiz-Osmanlı rekabeti, salt bir güç çatışması değil, aynı zamanda iki farklı deniz hakimiyeti anlayışının karşılaşmasıydı. Portekizliler okyanus rotaları üzerinde tam denetim kurmayı hedeflerken, Osmanlılar Kızıldeniz ve körfez ağzını kontrol ederek geleneksel İslam ticaret ağlarını yaşatmayı amaçlıyordu.\"</i> [cite: 409]<br><br><b>Bu metni esas alarak iki gücün deniz hakimiyeti anlayışlarını karşılaştırınız. Bu iki stratejik yaklaşımın sonuçlarını değerlendirerek hangisinin daha kalıcı bir başarı sağladığını tartışınız.</b>",
        cevap: "Portekiz stratejik boğazlarda 'açık deniz hakimiyeti' kurmaya çalışırken, Osmanlı 'kapalı deniz' (Kızıldeniz ve Körfez) girişlerini koruyarak geleneksel ağları yaşatmayı hedeflemiştir[cite: 463]. Portekiz kısa vadeli ticari üstünlük sağlasa da, Osmanlı stratejisi geleneksel ağların Hollanda dönemine kadar kısmen hayatta kalmasını mümkün kılmıştır[cite: 463]."
    },
    {
        soru: "<i>\"Sömürge ekonomisi, yalnızca hammadde akışını değil, emek akışını da yeniden düzenledi. Atlantik köle ticareti, zorla taşınan milyonlarca Afrikalı ile birlikte tarihte görülmemiş bir 'emek sömürüsü' modeli oluşturdu; bu model, kapitalist ekonominin temel birikim süreçlerinden birine zemin hazırladı.\"</i> [cite: 413]<br><br><b>Bu metni esas alarak sömürge ekonomisinde 'emek sömürüsü'nün rolünü açıklayınız. Bu sürecin Osmanlı coğrafyasından geçen farklı emek pratikleriyle karşılaştırınız.</b>",
        cevap: "Atlantik köleliği, plantation ürünlerinin düşük maliyetle üretilmesini sağlayan kalıtsal ve ırksal bir sömürü modelidir[cite: 465]. Osmanlı'da ise emek plantation yerine çift-hane ve lonca sistemiyle örgütlenmiş; kölelik ise ırka dayanmayan ve toplumsal yükselmeye açık (örn. devşirme) daha esnek bir yapıda kalmıştır[cite: 465]."
    },
    {
        soru: "<i>\"Osmanlı tağşiş politikası, kısa vadeli bütçe açıklarını kapatmanın bir aracıydı; ancak bu uygulamanın uzun vadeli sonucu, akçeye duyulan güvenin sarsılması ve enflasyonun kontrolden çıkmasıydı. Böylece devlet, ekonomik sorunu çözmeye çalışırken onu derinleştirdi.\"</i> [cite: 416]<br><br><b>Pamuk'un bu tespitinden hareketle Osmanlı para politikasının dönemin küresel ekonomik değişimleriyle (Fiyat Devrimi, gümüş akışı) nasıl etkileşime girdiğini açıklayınız. Tağşiş politikasının hangi ekonomik ve sosyal sonuçlara yol açtığını tartışınız.</b>",
        cevap: "Para tağşişi, küresel gümüş akışının yarattığı fiyat artışlarıyla çakışarak enflasyonu körüklemiştir[cite: 467]. Sonuçta sabit gelirli sipahi, ulema ve zanaatkarlar reel gelir kaybı yaşamış; bu durum sosyal hoşnutsuzluğu artırarak Celali İsyanlarının ekonomik zeminini hazırlamıştır[cite: 467]."
    },
    {
        soru: "<i>\"XVI. yüzyılın sonunda Osmanlı ordusu, tüfekli piyade birliklerini büyük ölçüde benimsemiş ve Avrupalı 'askeri devrim'in temel unsurlarına uyum sağlamıştı. Bu uyum süreci, Osmanlı'nın salt geleneksel ve değişime kapalı bir güç olduğu mitini çürütmektedir.\"</i> [cite: 420]<br><br><b>Bu metni esas alarak Osmanlı'nın askeri değişimlere uyum kapasitesini değerlendiriniz. Askeri alandaki uyumun ekonomik ve kurumsal alanlarda neden aynı hızla gerçekleşmediğini tartışınız.</b>",
        cevap: "Osmanlı tüfekli yeniçeri ve topçu teknolojisiyle askeri devrime başarıyla uyum sağlamıştır[cite: 469]. Ancak ekonomik uyum; tımar ve lonca gibi yerleşik güç dengelerini tehdit ettiği ve köklü mülkiyet değişimleri gerektirdiği için askeri uyumun gerisinde kalmıştır[cite: 469]."
    },
    {
        soru: "<i>Özbaran: \"Osmanlı'nın Hint Okyanusu politikası, salt savunmacı değil; Portekiz ablukasını kırmaya yönelik aktif bir stratejiydi.\"<br>Casale: \"Osmanlı'nın 16. yüzyıldaki coğrafi keşif hamleleri... imparatorluğun gerçek bir 'keşif çağı' yaşadığını kanıtlamaktadır.\"</i> [cite: 424]<br><br><b>Özbaran ve Casale'nin tezlerini karşılaştırarak Osmanlı'nın 16. yüzyılda yaşanan küresel coğrafi keşifler sürecindeki yerini yeniden değerlendiriniz.</b>",
        cevap: "Her iki tarihçi de Osmanlı'yı pasif mağdur değil, aktif bir stratejik aktör olarak konumlandırır[cite: 471]. Casale coğrafi bilgi üretimine ve 'keşif' ruhuna, Özbaran ise somut deniz seferlerine odaklanarak 'Osmanlı gerilemesi' anlatısına karşı çoğulcu bir tarihsel kapasite vurgusu yaparlar[cite: 471]."
    },
    {
        soru: "<i>Wallerstein: \"Osmanlı, XVI. yüzyılda kapitalist dünya ekonomisinin dışında kalmayı başarmıştı...\"<br>Pamuk: \"Osmanlı'nın dünya ekonomisiyle bütünleşme süreci, bir 'merkez'den 'çevre'ye geçiş şeklinde değil; tarihsel özgüllükleri olan karmaşık bir bütünleşme biçiminde gerçekleşmiştir.\"</i> [cite: 428]<br><br><b>Wallerstein ve Pamuk'un Osmanlı'nın dünya ekonomisiyle ilişkisine dair yorumlarını karşılaştırınız.</b>",
        cevap: "Wallerstein yapısal dışsal baskılara ve merkezin çevresine düşmeye odaklanırken, Pamuk Osmanlı'nın 'seçici uyum' kapasitesini ve iç dinamiklerinin karmaşıklığını vurgular[cite: 473]. Pamuk'un yaklaşımı Osmanlı'yı pasif bir mağdur yerine direnen ve uyum sağlayan özgün bir aktör olarak yansıtır[cite: 473]."
    },
    {
        soru: "<i>Chakrabarty: \"Avrupa tarihini evrensel bir referans noktası olarak kurmak, diğer toplumları 'geri' ya da 'ileri' olarak konumlandırmayı zorunlu kılar...\"<br>Goody: \"Sömürgeci tarih yazımı... diğer medeniyetlerin kendi dinamiklerini ve katkılarını sistematik biçimde küçümsemiştir.\"</i> [cite: 432]<br><br><b>Chakrabarty ve Goody'nin metodolojik eleştirileri ışığında Osmanlı'nın sömürgecilik çağına verdiği tepkileri değerlendiriniz.</b>",
        cevap: "Eleştiriler ışığında Osmanlı 'neden geride kaldı' yerine 'ne yapmayı seçti' sorusuyla incelenmeli; sömürgeci anlatının görünmez kıldığı Osmanlı bilimsel ve stratejik katkıları gün yüzüne çıkarılmalıdır[cite: 475]. Fail-mağdur ikiliğini aşan, Osmanlı'nın özgül koşullarını (çok cepheli baskı vb.) şablonlara indirgemeyen bir yöntem izlenmelidir[cite: 475]."
    },
    {
        soru: "<i>\"Portekizliler, 15. yüzyılda Afrika kıyısını adım adım inerek hem coğrafi bilgi biriktirdiler hem de köle ve altın ticaretinden gelir elde ettiler. Madeira ve Azorlar gibi Atlantik adaları, şeker üretiminin ilk üslerine dönüştü; bu adalar bir bakıma gelecekteki Amerikan plantasyon ekonomisinin provası niteliğindeydi.\"</i> [cite: 534]<br><br><b>Bu metni esas alarak Portekiz'in 15. yüzyıldaki Afrika kıyısı seferlerinin sonraki sömürge ekonomisinin kurulmasında nasıl bir 'deneme alanı' işlevi gördüğünü açıklayınız. Madeira-Azorlar modelini kısaca değerlendiriniz.</b>",
        cevap: "Portekiz'in Atlantik adalarındaki şeker-köle-plantasyon uygulaması, Amerika'nın keşfinden sonra Karayipler ve Brezilya'da kurulacak olan sömürgeci plantasyon ekonomisinin kurumsal ve ekonomik şablonunu oluşturmuştur[cite: 612]."
    },
    {
        soru: "<i>\"Osmanlı Devleti, Portekiz tehlikesini yalnızca bir ticaret sorunu olarak değil, Mekke ve Medine'nin koruyuculuğu çerçevesinde dinî-siyasi bir mesele olarak da gördü. Hicaz'ın iaşesini ve Kızıldeniz güvenliğini tehdit eden her güce karşı çıkmak, Osmanlı sultanlarının halifelik rolünün bir gereğiydi.\"</i> [cite: 538]<br><br><b>Bu metin ışığında Osmanlı'nın Portekiz'e karşı tutumunda dinî meşruiyet ile stratejik çıkarın nasıl iç içe geçtiğini açıklayınız. Bu birlikteliğin Osmanlı politikasını nasıl güçlendirdiğini ya da kısıtladığını tartışınız.</b>",
        cevap: "Sultanın 'Hâdimü'l-Harameyn' unvanı, Portekiz tehdidine karşı hem bir koruma sorumluluğu (stratejik çıkar) hem de bir meşruiyet sınavı yaratmıştır[cite: 614]. Bu durum Osmanlı'yı Hint seferlerine zorlayarak meşruiyeti pekiştirmiş ancak bazen stratejik rasyonalitenin ötesinde maliyetli adımlara da (kısıt) yol açmıştır[cite: 614]."
    },
    {
        soru: "<i>\"Portekiz'in Estado da India'sı (Hindistan Devleti), denizaşırı toprakların yönetiminde alışılmadık bir model ortaya koydu: Büyük toprak kütleleri yerine stratejik liman noktalarının kontrolüne dayanan bu sistem, 'talassokrasi' yani deniz yolu üzerinden egemenlik anlayışını hayata geçiriyordu.\"</i> [cite: 542]<br><br><b>Estado da India modelini 'talassokrasi' kavramı çerçevesinde açıklayınız. Bu modelin güçlü ve zayıf yönlerini Osmanlı'nın kara imparatorluğu anlayışıyla karşılaştırarak değerlendiriniz.</b>",
        cevap: "Talassokrasi, toprak yerine limanları (Goa, Hürmüz, Malaka) kontrol eden deniz hakimiyetidir; az nüfusla yüksek etki sağlayan ancak iç bölgelere sızamayan kırılgan bir modeldir[cite: 616]. Osmanlı'nın toprak hakimiyeti derin idari altyapı sunarken, Portekiz'in deniz ağlarına dayalı modeli okyanus ticaretini denetlemeye daha uygundur[cite: 616]."
    },
    {
        soru: "<i>\"Atlantik köle ticareti ve plantation ekonomisi, İngiltere'nin sanayi devrimine zemin hazırlayan sermaye birikiminin temel kaynaklarından birini oluşturdu. Liverpool ve Bristol gibi liman kentlerinin zenginleşmesi, büyük ölçüde köle ticaretinden elde edilen kârlara dayanmaktaydı...\"</i> [cite: 545]<br><br><b>Eric Williams'ın bu tezini açıklayınız. Osmanlı'nın benzer bir 'ilk sermaye birikimi' sürecinden neden yoksun kaldığını değerlendiriniz.</b>",
        cevap: "Williams tezi, köle ticareti kârlarının sanayi devriminin finansmanında ve yönetim tekniklerinde belirleyici olduğunu savunur[cite: 618]. Osmanlı'da; ticaret burjuvazisinin gelişememesi, lonca sisteminin rekabeti kısıtlaması ve devletin 'iaşe' önceliği nedeniyle plantation benzeri bir sermaye birikim modeli oluşmamıştır[cite: 618]."
    },
    {
        soru: "<i>\"Hint Okyanusu, Portekizlilerden önce ticari güvenden beslenen açık bir sistemdi: Tüccarlar, yerleşik örf ve anlaşmalara dayanan kurallara göre hareket eder; taraflar arasında uzun vadeli güven ilişkileri sürerdi. Portekizlilerin şiddet tekelini dayatması bu güven düzenini sarstı...\"</i> [cite: 549]<br><br><b>Pearson'ın tanımladığı 'açık sistem'in ne anlama geldiğini açıklayınız. Portekiz müdahalesinin bu sistemi ne ölçüde dönüştürdüğünü ve ne ölçüde sürdürdüğünü tartışınız.</b>",
        cevap: "'Açık sistem', devlet zoru yerine tüccarlar arası güven ve örfe dayalı ticaret havzasıdır; Portekiz Kartaz (geçiş izni) yoluyla şiddet tekelini dayatmıştır[cite: 620]. Portekiz tüm ağları tasfiye edememiş, yerel tüccarlar Portekizle uzlaşarak veya alternatif yollarla sistemi kısmen sürdürmüştür; Osmanlı bu noktada geleneksel koruyuculuk rolü üstlenmiştir[cite: 620]."
    }
];
window.allTests = window.allTests || {};
window.allTests["test_u3_somurgeci_1"] = [
{soru: "<i>\"Osmanlı Devleti, 15. ve 16. yüzyıllarda üç kıtaya yayılan toprakları üzerinde ticaret akışlarını denetim altına alarak vergi ve geçiş ücreti gelirlerinden büyük kazanımlar elde etti. Ancak Avrupa'nın deniz aşırı keşiflerinin yarattığı ticaret yolu değişimi, bu denetimin stratejik değerini kademeli olarak düşürdü. Osmanlı'nın güç merkezine coğrafi olarak uzak olan güzergahlar; Hint Okyanusu ve Atlas Okyanusu kıyıları, kontrolün dışında kaldı.\"</i><br><br><b>Kafesoğlu'nun bu değerlendirmesine göre Osmanlı'nın coğrafi konumu, ticaret yolu değişiminin etkilerini hangi açıdan sınırladı?</b>", secenekler: ["A) Osmanlı'nın merkezine uzak olan Hint Okyanusu ve Atlas Okyanusu güzergahları üzerinde denetim kuramaması, ticaret yolu değişiminin yaratacağı stratejik zararı bertaraf etme imkânını kısıtladı.","B) Osmanlı, coğrafi merkezi konumu sayesinde her iki yeni güzergah üzerinde de denetim kurarak ticaret değişiminden kazançlı çıktı.","C) Coğrafi konum Osmanlı için avantaj oluşturdu; çünkü uzak güzergahların önemsizleşmesi Osmanlı'nın güçlü olduğu kara ticaretini ön plana çıkardı.","D) Osmanlı, coğrafi uzaklığa rağmen Hint Okyanusu ve Atlas Okyanusu'nda donanma üsleri kurarak denetimi eline geçirdi.","E) Kafesoğlu, coğrafi konum yerine idari yetersizliği temel sorun olarak öne çıkarmaktadır."], cevap: "A) Osmanlı'nın merkezine uzak olan Hint Okyanusu ve Atlas Okyanusu güzergahları üzerinde denetim kuramaması, ticaret yolu değişiminin yaratacağı stratejik zararı bertaraf etme imkânını kısıtladı.", aciklama: "Kafesoğlu, Osmanlı'nın güç merkezine coğrafi olarak uzak olan Hint Okyanusu ve Atlas Okyanusu güzergahlarının denetim dışı kaldığını ve bu durumun stratejik değeri düşürdüğünü belirtmektedir[cite: 734, 904]."},
{soru: "<i>\"Osmanlı, 15. ve 16. yüzyıllarda Doğu Akdeniz'de uluslararası ticareti biçimlendiren en güçlü aktördü. Ne var ki Batı Avrupa'da şekillenen kapitalist ticaret anlayışı, kâr güdüsünü, bireysel girişimciyi ve kurumsal yeniliği ticaretin merkezine koyarken Osmanlı geleneği bu unsurları devlet denetimi ve dinî kurallar çerçevesinde sınırlandırıyordu. Bu ayrım, Osmanlı'nın uzun vadede sömürgeci Avrupa'nın yarattığı yeni ticaret düzenine uyum sağlamasını güçleştirdi.\"</i><br><br><b>Braudel'in bu çözümlemesine göre Osmanlı'nın sömürgeci Avrupa'nın yarattığı ticaret düzenine uyum güçlüğünün temelinde yatan etken nedir?</b>", secenekler: ["A) Osmanlı'nın liman kentlerinin Akdeniz ticaretine yetersiz altyapı sunması.","B) Osmanlı'nın yüksek askeri harcamaları nedeniyle ticaret yatırımlarına kaynak ayıramaması.","C) Osmanlı'nın kâr güdüsünü, bireysel girişimciyi ve kurumsal yeniliği sınırlayan devlet denetimi ve dinî kural çerçevesinin, kapitalist ticaret anlayışının gerektirdiği esneklikle çelişmesi.","D) Osmanlı tüccarlarının bilinçli olarak uluslararası piyasalardan çekilmeyi tercih etmesi.","E) Osmanlı'nın Avrupa'ya olan coğrafi yakınlığının ticaret dengesini olumsuz etkilemesi."], cevap: "C) Osmanlı'nın kâr güdüsünü, bireysel girişimciyi ve kurumsal yeniliği sınırlayan devlet denetimi ve dinî kural çerçevesinin, kapitalist ticaret anlayışının gerektirdiği esneklikle çelişmesi.", aciklama: "Braudel, Osmanlı'nın devlet denetimi ve dinî kurallar çerçevesinin kâr güdüsünü ve bireysel girişimciyi sınırladığını, bunun da Avrupa kapitalist ticaret anlayışına uyumu güçleştirdiğini vurgular[cite: 742, 905]."},
{soru: "<i>\"17. yüzyılın ortalarında yabancı sikkelerin Osmanlı pazarlarına girişi o kadar yaygınlaştı ki Osmanlı devleti, kendi akçesinin dolaşımdaki payını denetlemekte güçlük çekti. Vergi dairelerinin kayıtları, giderek artan miktarda İspanyol gümüş riyali ve Venedik dükatının Anadolu'dan İstanbul'a uzanan ticaret güzergahlarında tedavülde olduğunu ortaya koymaktadır. Bu durum, Osmanlı'nın para politikası bağımsızlığını fiilen kısıtladı.\"</i><br><br><b>Bu kaynağa dayanarak 17. yüzyılda Osmanlı para sisteminde yaşanan dönüşümün temel sonucu nasıl tanımlanabilir?</b>", secenekler: ["A) Yabancı sikkelerin yaygınlaşması, Osmanlı akçesinin değerini artırmış ve devletin vergi gelirlerini yükseltmiştir.","B) Osmanlı, yabancı sikkelerin dolaşımını tamamen yasaklayarak para piyasasındaki egemenliğini korumuştur.","C) Yabancı sikkelerin Osmanlı pazarlarına geniş ölçüde sızması, devletin kendi para birimi üzerindeki denetimini ve para politikası bağımsızlığını fiilen kısıtlamıştır.","D) İspanyol gümüş riyali ve Venedik dükatının yaygınlaşması, Osmanlı tüccarlarına dış ticarette rekabet avantajı sağlamıştır.","E) Yabancı sikkelerin dolaşımı, yalnızca İstanbul'la sınırlı kalmış; Anadolu ticaret güzergahları bu süreçten etkilenmemiştir."], cevap: "C) Yabancı sikkelerin Osmanlı pazarlarına geniş ölçüde sızması, devletin kendi para birimi üzerindeki denetimini ve para politikası bağımsızlığını fiilen kısıtlamıştır.", aciklama: "Kaynak metin, yabancı sikkelerin yaygın dolaşımının Osmanlı'nın kendi para birimi üzerindeki denetimini ve para politikası bağımsızlığını fiilen kısıtladığını açıkça belirtir[cite: 750, 906]."},
{soru: "<i>\"Portekiz İmparatorluğu'nun Asya'daki yapısı, İberya Yarımadası'ndaki metropol devletin uzantısı olmaktan çok, kendi içinde parçalı ve yerel güçlerle sürekli müzakere içinde olan bir örgütlenme biçimiydi. Portekiz görevlileri sık sık kişisel çıkarlarını imparatorluk politikasının önüne koydu; bu durum 'resmi' sömürge politikasının fiiliyattaki uygulamasını tutarsız kıldı.\"</i><br><br><b>Subrahmanyam'ın bu tespitini Osmanlı'nın Portekiz'le mücadelesini anlama bağlamında değerlendirdiğimizde, Portekiz'in Hint Okyanusu'ndaki 'hâkimiyeti'ne ilişkin ne söylenebilir?</b>", secenekler: ["A) Portekiz'in parçalı örgütlenme yapısı ve tutarsız uygulaması, Osmanlı ve Müslüman tüccarların bu sistemi aşmaları için fırsatlar yarattı.","B) Portekiz, parçalı yapısına rağmen Hint Okyanusu'nda tam ve istisnasız bir ticaret tekeli kurarak Osmanlı'yı bölgeden tamamen dışladı.","C) Subrahmanyam, Portekiz'in Osmanlı karşısında askeri açıdan her zaman üstün olduğunu ve bu üstünlüğün tutarsız yönetimi telafi ettiğini savunmaktadır.","D) Portekiz görevlilerinin kişisel çıkarlarını öne çıkarması, aslında Osmanlı-Portekiz ilişkilerini siyasi düzeyden kişisel ortaklık düzeyine taşıdı.","E) Portekiz'in parçalı yapısı, Hint Okyanusu'ndaki Osmanlı faaliyetlerini tamamen etkisiz kıldı."], cevap: "A) Portekiz'in parçalı örgütlenme yapısı ve tutarsız uygulaması, Osmanlı ve Müslüman tüccarların bu sistemi aşmaları için fırsatlar yarattı.", aciklama: "Subrahmanyam'ın belirttiği parçalı yapı ve tutarsızlıklar, Osmanlı ve Müslüman tüccarların Portekiz tekelini delmeleri ve alternatif yollar kullanmaları için imkanlar oluşturmuştur[cite: 758, 907]."},
{soru: "<i>\"Osmanlı ekonomisinin dünya kapitalizmiyle eklemlenmesini tek yönlü bir sömürgeleştirme süreciyle açıklamak yetersiz kalır. Osmanlı devletinin ekonomi yönetimindeki müdahaleci kapasitesi, Avrupa merkezli ticaret ağlarının Osmanlı pazarlarına nüfuzunu düzenleyebildi ve kısmen sınırlandırabildi. Bu durum, Osmanlı'nın edilgen bir nesne olmadığını; değişen koşullara kendi kurumsal mantığı içinde tepki veren bir özne konumunda kaldığını göstermektedir.\"</i><br><br><b>İslamoğlu-İnan'ın editörlüğündeki bu eserin çerçevesine göre Osmanlı'nın dünya ekonomisiyle ilişkisi nasıl tanımlanmalıdır?</b>", secenekler: ["A) Osmanlı, Avrupa kapitalizminin sömürgeleştirme sürecinde tamamen edilgen bir nesne konumuna düşmüştür.","B) Osmanlı'nın müdahaleci ekonomi yönetim kapasitesi, Avrupa ticaret ağlarının nüfuzunu düzenleyip sınırlayabilmiş; Osmanlı bu süreçte kendi kurumsal mantığıyla tepki veren bir özne konumunda kalmıştır.","C) Osmanlı, Avrupalı ticaret ağlarını tamamen dışarıda bırakarak bağımsız bir ulusal ekonomi kurmuştur.","D) İslamoğlu-İnan, dünya ekonomisiyle eklemlenmenin Osmanlı'ya yalnızca olumlu katkı sağladığını savunmaktadır.","E) Osmanlı devletinin ekonomi yönetimindeki müdahaleci kapasitesi 17. yüzyılda Avrupalı devletlerin kapasitesinin çok üzerindeydi."], cevap: "B) Osmanlı'nın müdahaleci ekonomi yönetim kapasitesi, Avrupa ticaret ağlarının nüfuzunu düzenleyip sınırlayabilmiş; Osmanlı bu süreçte kendi kurumsal mantığıyla tepki veren bir özne konumunda kalmıştır.", aciklama: "Metne göre Osmanlı ekonomisi edilgen bir kurban değil, müdahaleci kapasitesiyle Avrupa ticaret ağlarını düzenleyen ve kendi mantığıyla tepki veren bir öznedir[cite: 767, 908]."},
{soru: "<i>\"Kahire, 16. yüzyılın sonlarına gelindiğinde Osmanlı idaresi altında Doğu-Batı ticaretinin belirli bir aktarma işlevi üstlenmeyi sürdürmekteydi. Ancak bu işlev, daha önceki Memlük dönemine kıyasla belirgin biçimde zayıflamıştı. Portekiz'in Hint Okyanusu'ndaki varlığının kısmî olduğu dönemlerde Kızıldeniz-Kahire-İskenderiye güzergahı hâlâ kullanılabilirken, bu varlığın yoğunlaştığı dönemlerde ticaret hacmi dramatik biçimde düşüyordu.\"</i><br><br><b>Raymond'ın bu tespitine göre Kahire'nin ticaret aktarım işlevinin Osmanlı dönemindeki seyri nasıl açıklanabilir?</b>", secenekler: ["A) Kahire, Osmanlı döneminde Memlük dönemine kıyasla çok daha güçlü bir ticaret merkezi konumuna yükselmiştir.","B) Kahire'nin ticaret aktarım işlevi, Portekiz'in Hint Okyanusu'ndaki varlığının yoğunluğuyla doğrudan ilişkili olarak dalgalanmış ve Memlük dönemine kıyasla genel olarak zayıflamıştır.","C) Portekiz'in Hint Okyanusu'ndaki varlığı Kahire'nin ticaretini hiç etkilemedi; çünkü Kızıldeniz güzergahı Portekiz'in erişiminin dışındaydı.","D) Kahire, Osmanlı yönetimi altında Doğu-Batı ticaretinin tüm işlevini yitirdi ve Osmanlı tarafından bilinçli olarak devre dışı bırakıldı.","E) Raymond, Kahire'nin ticaret hacmindeki dalgalanmanın Portekiz'in varlığından değil yalnızca Osmanlı iç politikalarından kaynaklandığını savunmaktadır."], cevap: "B) Kahire'nin ticaret aktarım işlevi, Portekiz'in Hint Okyanusu'ndaki varlığının yoğunluğuyla doğrudan ilişkili olarak dalgalanmış ve Memlük dönemine kıyasla genel olarak zayıflamıştır.", aciklama: "Raymond, Kahire'nin ticaret hacminin Portekiz'in Hint Okyanusu'ndaki varlık yoğunluğuna paralel olarak değişim gösterdiğini ve Memlük döneminin altına düştüğünü saptamaktadır[cite: 776, 909]."},
{soru: "<i>\"16. yüzyılın ikinci yarısından itibaren Osmanlı devleti, Avrupa ile olan denizaşırı ticaret dengesizliğini giderek daha belirgin biçimde hissetmeye başladı. Avrupa'dan ithal edilen kumaş, cam ve metal ürünler ile bu malların sağlandığı kaynaklardan elde edilen değerli maden akışı, Osmanlı'nın geleneksel ihracat ürünleri olan hammadde ve tarımsal ürünlerle karşılaştırıldığında katma değer açısından giderek belirginleşen bir eşitsizlik yarattı.\"</i><br><br><b>Kreiser ve Neumann'ın bu değerlendirmesine göre Osmanlı ile Avrupa arasındaki ticaret dengesi 16. yüzyılın ikinci yarısında nasıl bir yapı sergilemiştir?</b>", secenekler: ["A) Osmanlı, Avrupa'ye işlenmiş mallar ihraç ederken Avrupa'dan yalnızca hammadde ithal ettiğinden ticaret dengesi Osmanlı lehine seyretmiştir.","B) Osmanlı, Avrupa'dan işlenmiş, yüksek katma değerli ürünler ithal ederken düşük katma değerli hammadde ve tarımsal ürünler ihraç etmekte; bu durum eşitsiz bir ticaret yapısı ortaya çıkarmaktadır.","C) Kreiser ve Neumann, Osmanlı-Avrupa ticaret dengesinin her iki taraf için de eşit biçimde kârlı olduğunu savunmaktadır.","D) Avrupa'nın Osmanlı'ya ihraç ettiği mallar yalnızca lüks tüketim ürünleri kategorisinde kalmakta olup ekonomik dengeye etkisi ihmal edilebilir düzeydeydi.","E) Osmanlı, 16. yüzyılın ikinci yarısında Avrupa ile ticaretten tamamen çekilmiş ve Asya piyasalarına yönelmiştir."], cevap: "B) Osmanlı, Avrupa'dan işlenmiş, yüksek katma değerli ürünler ithal ederken düşük katma değerli hammadde ve tarımsal ürünler ihraç etmekte; bu durum eşitsiz bir ticaret yapısı ortaya çıkarmaktadır.", aciklama: "Metin, 16. yüzyılın ikinci yarısında ithal edilen işlenmiş mallar ile ihraç edilen hammadde arasındaki katma değer farkının yarattığı eşitsiz ticaret yapısına dikkat çeker[cite: 784, 910]."},
{soru: "<i>\"17. yüzyılda Osmanlı'da gelişen iltizam sistemi, yani vergi toplama haklarının ihale yoluyla özel kişilere devredilmesi; bir yandan merkezi hazinenin nakit ihtiyacını anlık olarak karşılarken öte yandan vergi tabanının uzun vadeli aşınmasına zemin hazırladı. Bu sistemin yaygınlaşmasının temelinde, sömürgeci Avrupa'nın yarattığı gelir baskısının merkezî hazineyi kısa vadeli çözümlere yöneltmesi yatıyordu.\"</i><br><br><b>Salzmann'ın bu analizine göre iltizam sisteminin 17. yüzyılda yaygınlaşmasının Osmanlı maliyesi üzerindeki çelişkili etkisi nasıl tanımlanabilir?</b>", secenekler: ["A) İltizam sistemi, hem kısa hem de uzun vadede Osmanlı maliyesini güçlendiren bir yenileşme aracı olarak işlev görmüştür.","B) İltizam sistemi, Osmanlı'nın vergi toplamasını bütünüyle özel sektöre bıraktığı anlamına geliyordu.","C) İltizam sisteminin kısa vadede anlık nakit ihtiyacını giderirken uzun vadede vergi tabanını aşındırması, sömürgeci baskıların tetiklediği kısa vadeci mali reflekslerin yapısal bedeline işaret etmektedir.","D) Salzmann, iltizam sistemini Osmanlı'nın sömürgeci Avrupa'ya karşı bilinçli olarak geliştirdiği bir mali savunma mekanizması olarak tanımlamaktadır.","E) İltizam sisteminin yaygınlaşması, Osmanlı'nın Avrupalı tüccarlardan aldığı vergileri artırarak dış ticaret dengesini düzeltmesine katkı sağlamıştır."], cevap: "C) İltizam sisteminin kısa vadede anlık nakit ihtiyacını giderirken uzun vadede vergi tabanını aşındırması, sömürgeci baskıların tetiklediği kısa vadeci mali reflekslerin yapısal bedeline işaret etmektedir.", aciklama: "Salzmann, sömürgeci baskılar sonucu hazinenin kısa vadeli nakit ihtiyacına yönelmesinin, vergi tabanını aşındıran iltizam sistemi gibi yapısal sorunlara yol açtığını savunur[cite: 793, 911]."},
{soru: "<i>\"Osmanlı'nın iç kara yollarını korumaya yönelik derbend teşkilatı, devletin ticaret güzergahları üzerindeki güvenlik sorumluluğunu doğrudan yerine getirdiğinin somut göstergesiydi. Ancak 17. yüzyılın başlarından itibaren mali kısıtların etkisiyle derbend teşkilatına ayrılan kaynaklar azaldı; yol güvenliği zayıfladı ve iç ticaret ağlarının verimliliği düştü. Bu gerileme, dış güzergah kayıplarından bağımsız olarak iç ekonomik döngüleri de olumsuz etkiledi.\"</i><br><br><b>Orhonlu'nun bu tespitine göre Osmanlı'nın iç ticaret altyapısındaki gerilemenin dışsal sömürgeci baskılarla ilişkisi nasıl kurulabilir?</b>", secenekler: ["A) Derbend teşkilatının çöküşü, Avrupa sömürgeciliğinden tamamen bağımsız olup yalnızca iç yönetim hatalarından kaynaklanmaktadır.","B) Sömürgeci ticaret yolu değişiminin yarattığı mali baskı, derbend teşkilatı gibi iç ticaret altyapısına ayrılan kaynakları azaltarak iç ekonomik döngüleri de dolaylı olarak olumsuz etkiledi.","C) Osmanlı, derbend teşkilatını Avrupalı tüccarlara karşı doğrudan bir savunma aracı olarak kullandı.","D) Derbend teşkilatındaki kaynak azalması, merkezi hazineyi güçlendirmek amacıyla bilinçli olarak yapılan bir tasarruf kararıydı.","E) Orhonlu, derbend teşkilatının 17. yüzyılda daha da güçlendiğini ve iç ticaret ağlarını başarıyla koruduğunu belgelemektedir."], cevap: "B) Sömürgeci ticaret yolu değişiminin yarattığı mali baskı, derbend teşkilatı gibi iç ticaret altyapısına ayrılan kaynakları azaltarak iç ekonomik döngüleri de dolaylı olarak olumsuz etkiledi.", aciklama: "Dış ticaret yollarının kaymasının yarattığı mali baskı, iç güvenliği sağlayan derbend teşkilatına ayrılan kaynakları kısıtlayarak iç ticaretin de zarar görmesine neden olmuştur[cite: 801, 912]."},
{soru: "<i>\"Osmanlı'nın 17. yüzyıldaki ekonomik güçlükleri, bazı tarihçilerin ileri sürdüğünün aksine, Osmanlı'nın daha önceki dönemlerde sahip olduğu ekonomik dinamizmin salt bozulması değildi. Daha ziyade, Avrupa merkezli ekonomik sistemin yeniden yapılandırdığı küresel bağlantılar çerçevesinde Osmanlı'nın maruz kaldığı bir yeniden konumlanma sürecinin ürünüydü.\"</i><br><br><b>Quataert'ın bu değerlendirmesine göre Osmanlı'nın 17. yüzyıl ekonomik güçlüklerini 'salt bozulma' olarak nitelendirmenin hangi metodolojik sınırlılığı bulunmaktadır?</b>", secenekler: ["A) Salt bozulma çerçevesi, Osmanlı ekonomisinin hiç dinamizm içermediğini ima eder.","B) Salt bozulma yorumu, Avrupa merkezli ekonomik yeniden yapılanmanın Osmanlı'yı nasıl yeniden konumlandırdığını göz ardı ederek güçlükleri yalnızca içsel gerilemeyle açıklamaktadır.","C) Salt bozulma çerçevesi, Osmanlı'yı ekonomik açıdan her dönemde istikrarlı bir güç olarak tanımlar ve değişimi kabul etmez.","D) Quataert, bozulma yorumunu bütünüyle reddetmekte ve Osmanlı'nın 17. yüzyılda ekonomik gücünü tam anlamıyla koruduğunu savunmaktadır.","E) Salt bozulma yorumu yalnızca Marksist tarih yazımına özgüdür."], cevap: "B) Salt bozulma yorumu, Avrupa merkezli ekonomik yeniden yapılanmanın Osmanlı'yı nasıl yeniden konumlandırdığını göz ardı ederek güçlükleri yalnızca içsel gerilemeyle açıklamaktadır.", aciklama: "Quataert, ekonomik sorunların salt bir iç 'bozulma' olmadığını, küresel sistemdeki yeniden yapılanmanın Osmanlı'yı ittiği yeni konumun sonucu olduğunu vurgular[cite: 809, 913]."},
{soru: "<i>\"Osmanlı merkezi hazinesinin 1560–1660 dönemindeki gelir-gider kayıtları, bu yüzyıllık süreçte devletin giderek artan bir gelir açığıyla mücadele ettiğini ortaya koymaktadır. Gelirlerin azalmasında birden fazla etken rol oynadı: Vergi tabanının daralması, akçe devalüasyonu, taşra vergi toplayıcılarının merkezle paylaşmaktan kaçındığı artı değer ve ticaret yollarının kaymasına bağlı gümrük gelirlerindeki düşüş bunların başında gelmektedir.\"</i><br><br><b>Darling'in bu tespitine göre Osmanlı hazinesinin 16. yüzyılın sonları ile 17. yüzyılın başlarında yaşadığı gelir açığının kaynaklarından biri olan ticaret yollarının kayması, diğer etkenlerle nasıl bir ilişki içindedir?</b>", secenekler: ["A) Ticaret yollarının kayması, Osmanlı gelir açığının tek ve belirleyici nedenidir.","B) Ticaret yollarının kayması, Osmanlı hazine krizine birden fazla etkenin katkıda bulunduğu yapısal bir tablonun yalnızca bir bileşeni olarak işlev görmekte; akçe devalüasyonu ve taşra düzeyindeki kayıplarla birlikte birleşik bir baskı oluşturmaktadır.","C) Ticaret yollarının kayması Osmanlı gelirlerini etkilememiştir; gümrük gelirleri bu dönemde aksine artmıştır.","D) Darling, yalnızca taşra vergi toplayıcılarının yolsuzluklarını gelir açığının kaynağı olarak tespit etmektedir.","E) Osmanlı merkezi hazinesi, bu dönemde ticaret yollarının kaymasını bilinçli olarak telafi eden alternatif gelir kaynakları yaratmayı başarmıştır."], cevap: "B) Ticaret yollarının kayması, Osmanlı hazine krizine birden fazla etkenin katkıda bulunduğu yapısal bir tablonun yalnızca bir bileşeni olarak işlev görmekte; akçe devalüasyonu ve taşra düzeyindeki kayıplarla birlikte birleşik bir baskı oluşturmaktadır.", aciklama: "Darling, ticaret yollarının kaymasının hazine krizindeki çok nedenli yapısal tablonun (devalüasyon, vergi kaçağı vb.) bileşenlerinden biri olduğunu ortaya koyar[cite: 817, 914]."},
{soru: "<i>\"Osmanlı'nın kuzey ticaret güzergahlarındaki konumu, özellikle Karadeniz üzerinden Orta Asya ve İran ile kurulan bağlantı, sömürgeci güçlerin taarruzunun görece dışında kaldı. Bu güzergah, Portekiz ve İspanya'nın nüfuzunun ulaşmadığı bir bölgeyi temsil ediyordu. Osmanlı, bu güzergah üzerindeki kontrolü kısmen sürdürürken Akdeniz ve Hint Okyanusu'ndaki konumunu yitirmeye devam etti.\"</i><br><br><b>Bu değerlendirmeye göre Osmanlı'nın 16. ve 17. yüzyıllardaki ticari kayıpları coğrafi açıdan nasıl bir dağılım sergilemiştir?</b>", secenekler: ["A) Osmanlı, Karadeniz-Orta Asya-İran güzergahlarında da büyük kayıplar yaşamış; tüm ticaret ağları bu dönemde çöküntüye uğramıştır.","B) Osmanlı, Akdeniz ve Hint Okyanusu güzergahlarında konumunu yitirirken sömürgeci güçlerin ulaşamadığı Karadeniz-Orta Asya güzergahı üzerindeki denetimini kısmen koruyabilmiştir.","C) Portekiz ve İspanya'nın Karadeniz güzergahına nüfuz etmesi, Osmanlı'nın bu alandaki konumunu da büyük ölçüde zayıflattı.","D) Osmanlı, Akdeniz'deki kaybını tamamen telafi etmeyi başarmış ve Karadeniz güzergahı aracılığıyla ekonomik gücünü yeniden inşa etmiştir.","E) Osmanlı'nın Karadeniz güzergahı, sömürgeci baskılardan korunmuş olmasına rağmen Osmanlı devleti bu güzergahı ihmal etmiştir."], cevap: "B) Osmanlı, Akdeniz ve Hint Okyanusu güzergahlarında konumunu yitirirken sömürgeci güçlerin ulaşamadığı Karadeniz-Orta Asya güzergahı üzerindeki denetimini kısmen koruyabilmiştir.", aciklama: "Metin, sömürgeci güçlerin nüfuzunun ulaşamadığı Karadeniz-Kuzey güzergahının, kayıpların yaşandığı güney denizlerinden farklı olarak kontrol altında tutulabildiğini vurgular[cite: 826, 915]."},
{soru: "<i>\"Osmanlı'nın 16. ve 17. yüzyıllarda Doğu Avrupa devletleriyle (Polonya, Venedik, Fransa) yürüttüğü diplomatik ilişkiler, salt güvenlik ve toprak meselelerinin ötesine geçen ticari ve stratejik bir boyut taşıyordu. Bu ilişkilerde Osmanlı, Avrupa içindeki güç dengesini kendi çıkarı doğrultusunda yönetmeye çalışarak İspanya ve Kutsal Roma İmparatorluğu'na karşı bir karşı ağırlık politikası izledi.\"</i><br><br><b>Kołodziejczyk'ın bu tespitine göre Osmanlı'nın bazı Avrupa devletleriyle sürdürdüğü diplomatik ilişkiler, sömürgeci güçlerle mücadele bağlamında nasıl değerlendirilebilir?</b>", secenekler: ["A) Osmanlı, Avrupa devletleriyle yalnızca ticari anlaşmalar imzalamış; siyasi veya stratejik bir hesap bulunmamaktadır.","B) Osmanlı'nın Polonya, Venedik ve Fransa gibi devletlerle geliştirdiği diplomatik ilişkiler, İspanya ve Kutsal Roma İmparatorluğu'na karşı dengeleme stratejisinin bir parçası olarak sömürgeci güçlerin Osmanlı üzerindeki baskısını dolaylı olarak sınırlamaya katkıda bulunmuştur.","C) Osmanlı, İspanya ve Portekiz ile de ittifak kurarak denizaşırı sömürge hâkimiyetinde ortak çıkar elde etmeyi başarmıştır.","D) Osmanlı diplomasisi, 16. ve 17. yüzyıllarda yalnızca Osmanlı'nın toprak genişlemesine hizmet etmiştir.","E) Kołodziejczyk, Osmanlı-Polonya ilişkisini salt kültürel temasın bir ürünü olarak değerlendirmektedir."], cevap: "B) Osmanlı'nın Polonya, Venedik ve Fransa gibi devletlerle geliştirdiği diplomatik ilişkiler, İspanya ve Kutsal Roma İmparatorluğu'na karşı dengeleme stratejisinin bir parçası olarak sömürgeci güçlerin Osmanlı üzerindeki baskısını dolaylı olarak sınırlamaya katkıda bulunmuştur.", aciklama: "Osmanlı, Avrupa içindeki diplomatik manevraları ve dengeleme politikasını (özellikle Habsburg karşıtı ittifaklar), sömürgeci rakiplerine karşı stratejik bir araç olarak kullanmıştır[cite: 834, 916]."},
{soru: "<i>\"Osmanlı'nın 17. yüzyıl sonundaki diplomatik müzakereleri, devletin artık eski koşulsuz egemenlik iddiasından uzaklaşarak daha müzakereci ve uzlaşmacı bir zemine kaymakta olduğunu yansıtmaktadır. Bu kayma, yalnızca askeri yenilgilerin sonucu değil; aynı zamanda Avrupa sömürgeciliğinin yarattığı ekonomik gerileme ortamında Osmanlı'nın müzakere araçlarının zayıflamasının da bir göstergesiydi.\"</i><br><br><b>Abou-El-Haj'ın bu değerlendirmesine göre Osmanlı diplomasisindeki 17. yüzyıl sonu dönüşümünü açıklamada hangi çok nedenli perspektif benimsenmelidir?</b>", secenekler: ["A) Osmanlı'nın diplomasideki tavizci tutumu yalnızca askeri yenilgilerin doğrudan sonucudur.","B) Osmanlı diplomasisindeki dönüşüm, hem askeri yenilgilerin hem de sömürgeci baskıların yarattığı ekonomik gerilemenin müzakere araçlarını zayıflatıldığı çok nedenli bir sürecin ürünüdür.","C) Osmanlı, 17. yüzyıl sonunda Avrupa devletlerine yönelik diplomaside daha saldırgan bir tutum benimsedi.","D) Abou-El-Haj, müzakereye dayalı yeni diplomatik anlayışın Osmanlı'yı güçlendirdiğini savunmaktadır.","E) Osmanlı diplomasisindeki değişim, iç siyasi grupların politika tercihlerinin ürünüdür."], cevap: "B) Osmanlı diplomasisindeki dönüşüm, hem askeri yenilgilerin hem de sömürgeci baskıların yarattığı ekonomik gerilemenin müzakere araçlarını zayıflatıldığı çok nedenli bir sürecin ürünüdür.", aciklama: "Abou-El-Haj, diplomatik tutum değişikliğini sadece askeri başarısızlığa değil, sömürgecilik kaynaklı ekonomik zayıflamanın müzakere kapasitesini düşürmesine de bağlar[cite: 843, 917]."},
{soru: "<i>\"Osmanlı esnaf ve zanaat örgütlenmesi olan loncalar, 16. yüzyıla kadar iç piyasayı kalite denetimi ve üretim standardıyla düzenleyen işlevsel bir sistem oluşturuyordu. 17. yüzyılda Avrupa'dan gelen ucuz manifatura malları bu sistemi ciddi baskı altına aldı. Lonca kurumunun tepkisi ise ağırlıklı olarak geleneksel üretim standartlarını ve fiyat tarifelerini korumak yönünde oldu; bu tutum, değişen rekabet koşullarına yaratıcı bir uyum sağlamak yerine savunmacı bir pozisyon benimsenmesi anlamına geliyordu.\"</i><br><br><b>Ursinus'un bu analizine göre Osmanlı lonca kurumunun Avrupa rekabetine verdiği yanıtın temel niteliği nasıl tanımlanabilir?</b>", secenekler: ["A) Osmanlı loncaları, Avrupa rekabetine yaratıcı ürün yenilikleri ve maliyet düşürme stratejileriyle karşılık vererek rekabet güçlerini artırdı.","B) Osmanlı loncaları, Avrupa'dan gelen ucuz manifatura baskısı karşısında geleneksel standart ve tarifeleri koruma odaklı savunmacı bir tutum benimseyerek değişen rekabet koşullarına yaratıcı uyum sağlamakta yetersiz kaldı.","C) Loncalar, 17. yüzyılda faaliyetlerini tamamen terk ederek Osmanlı iç piyasasını Avrupa mallarına açık bir pazara dönüştürdü.","D) Osmanlı devleti, lonca kurumunu Avrupa rekabetine karşı korumak amacıyla kuvvetli gümrük tarifeleri uyguladı.","E) Ursinus, Osmanlı loncalarının 17. yüzyıldaki başarısını Avrupa rekabetine karşı sergilediği esnekliğe bağlamaktadır."], cevap: "B) Osmanlı loncaları, Avrupa'dan gelen ucuz manifatura baskısı karşısında geleneksel standart ve tarifeleri koruma odaklı savunmacı bir tutum benimseyerek değişen rekabet koşullarına yaratıcı uyum sağlamakta yetersiz kaldı.", aciklama: "Metne göre loncalar, Avrupa sanayi rekabetine karşı değişimi yakalamak yerine mevcut yapıyı korumaya odaklanan 'savunmacı' bir refleks göstermiştir[cite: 851, 918]."}
];
window.allTests = window.allTests || {};
window.allTests["test_u3_somurgeci_2"] = [
{soru: "<i>\"17. yüzyılda Osmanlı sarayındaki hanedan içi güç mücadelesi, 'Kadınlar Saltanatı' ve veziriazam devşirme ağlarının yoğunlaşmasına koşut olarak merkezi otoritenin görece gerilemesini yansıtıyordu. Bu süreç, dışsal ekonomik krizin yarattığı kaynak kısıtlarıyla iç içe geçerek devlet yönetimini giderek daha savunmacı ve reaktif bir konuma itti.\"</i><br><br><b>Peirce'ın bu değerlendirmesine göre 17. yüzyıl Osmanlı devlet yönetiminin savunmacı nitelik kazanması nasıl açıklanabilir?</b>", secenekler: ["A) Osmanlı devlet yönetiminin savunmacı nitelik kazanması yalnızca hanedan içi güç mücadelelerinin bir sonucudur.","B) Saraydaki hanedan içi güç mücadeleleri ile dışsal ekonomik krizin yarattığı kaynak kısıtları bir arada etkiyerek devlet yönetimini savunmacı ve reaktif bir konuma itmiştir.","C) Peirce, 17. yüzyıl Osmanlı devlet yönetiminin her yönüyle güçlendiğini ve her tehdidi başarıyla yönettiğini savunmaktadır.","D) Dışsal ekonomik kriz, saray içi güç mücadelelerini tamamen bastırarak devletin toparlayıcı bir liderlik sergilemesini sağladı.","E) Peirce, 'Kadınlar Saltanatı' kavramını salt tarihsel bir bağlamda ele almaktadır."], cevap: "B) Saraydaki hanedan içi güç mücadeleleri ile dışsal ekonomik krizin yarattığı kaynak kısıtları bir arada etkiyerek devlet yönetimini savunmacı ve reaktif bir konuma itmiştir.", aciklama: "Peirce, hem iç siyasi rekabetin (hanedan mücadeleleri) hem de dış ekonomik baskıların (kaynak kısıtı) yönetimi zayıflatarak savunmacı kıldığını belirtir[cite: 859, 919]."},
{soru: "<i>\"17. yüzyıl Osmanlı ansiklopedist ve coğrafyacısı Kâtip Çelebi, Cihannüma adlı eserinde Avrupa coğrafyasını ve keşif yolculuklarını tartışırken Osmanlı'nın bu coğrafi bilgiden geç yararlandığını ima etti. Ona göre Osmanlı'nın Hint Okyanusu ile Atlas Okyanusu'na ilişkin coğrafi bilgi eksikliği, fiilî strateji geliştirmenin önünde bir engel oluşturuyordu.\"</i><br><br><b>Kâtip Çelebi'nin bu tespiti, Osmanlı'nın deniz aşırı stratejik kapasitesinin gelişimini sınırlayan etkenler tartışmasına nasıl bir boyut eklemektedir?</b>", secenekler: ["A) Kâtip Çelebi, Osmanlı'nın okyanus coğrafyası konusundaki bilgi eksikliğinin stratejik sınırlamaya katkıda bulunduğuna dikkat çekerek salt ekonomik veya kurumsal açıklamaların yanına entelektüel-bilgisel bir boyut eklemektedir.","B) Kâtip Çelebi, Osmanlı'nın deniz gücünü Portekiz'in çok üstünde değerlendirerek gerçek sorunun bilgi eksikliği değil siyasi irade eksikliği olduğunu savunmaktadır.","C) Kâtip Çelebi, Avrupalı sömürgecilerin Osmanlı'ya coğrafi bilgi transferini engellediğini belgelemektedir.","D) Kâtip Çelebi'nin entelektüel katkısı, Osmanlı ekonomisini ilgilendirmemektedir.","E) Kâtip Çelebi, Osmanlı'nın okyanus coğrafyasını Avrupalılardan çok daha iyi bildiğini ortaya koymaktadır."], cevap: "A) Kâtip Çelebi, Osmanlı'nın okyanus coğrafyası konusundaki bilgi eksikliğinin stratejik sınırlamaya katkıda bulunduğuna dikkat çekerek salt ekonomik veya kurumsal açıklamaların yanına entelektüel-bilgisel bir boyut eklemektedir.", aciklama: "Kâtip Çelebi'nin uyarısı, stratejik yetersizliğin sadece maddi değil, okyanuslara dair entelektüel ve coğrafi bilgi birikimi eksikliğiyle de ilgili olduğunu gösterir[cite: 868, 920]."},
{soru: "<i>Kaynak A: \"16. yüzyılda Osmanlı'nın Orta Avrupa'daki askeri varlığı, İspanya ve Portekiz'in Avrupa'ya akan sömürge servetini yoğunlaştığı dönemle çakışıyordu. Bu askeri baskı, Avrupa devletlerinin Osmanlı'ya karşı savunma harcamalarını artırmasını zorunlu kıldı ve sömürge yatırımlarından kaynakları kısmen saptırdı.\"<br>Kaynak B: \"Osmanlı'nın Avrupa'ya yönelik askeri baskısının 'sömürgeci yayılımı frenleyip frenlememediği' sorusu, gerçekte yanıtlanması güç bir karşı-olgusal sorudur. Osmanlı baskısı olmasaydı sömürge yatırımlarının daha hızlı büyüyeceği varsayımı doğrulanamazken, baskının bu yatırımları kısmen saptırdığı da tamamen reddedilemez.\"</i><br><br><b>Coles ve Brummett'ın bu değerlendirmelerini karşılaştırarak Osmanlı'nın Avrupa'daki askeri varlığının Avrupa sömürgeciliğine etkisi konusundaki tarih yazımsal tartışmayı değerlendiriniz.</b>", secenekler: ["A) Coles ve Brummett her ikisi de Osmanlı'nın Avrupa sömürgeciliğini tamamen engellediği konusunda hemfikirdir.","B) Coles, Osmanlı baskısının sömürge yatırımlarını kısmen saptırdığını öne sürerken Brummett bu nedensellik ilişkisinin doğrulanmasının metodolojik açıdan güç olduğunu; kesin bir yargıdan kaçınmak gerektiğini vurgulamaktadır. Her iki yaklaşım da konunun tarih yazımındaki epistemolojik karmaşıklığını ortaya koymaktadır.","C) Brummett, Coles'un tezini bütünüyle doğrulamakta ve Osmanlı baskısının sömürge yatırımlarını belirgin biçimde engellediğini kesin olarak kabul etmektedir.","D) Coles, Osmanlı'nın Avrupa sömürgeciliği üzerinde hiçbir etkisi olmadığını savunmaktadır.","E) Her iki tarihçi de Osmanlı'nın askeri varlığını sömürgecilikle değil salt dinî çatışmayla açıklamaktadır."], cevap: "B) Coles, Osmanlı baskısının sömürge yatırımlarını kısmen saptırdığını öne sürerken Brummett bu nedensellik ilişkisinin doğrulanmasının metodolojik açıdan güç olduğunu; kesin bir yargıdan kaçınmak gerektiğini vurgulamaktadır. Her iki yaklaşım da konunun tarih yazımındaki epistemolojik karmaşıklığını ortaya koymaktadır.", aciklama: "İki metin arasındaki temel fark, Coles'un saptırma etkisine dair net iddiası ile Brummett'ın bu nedenselliğin kanıtlanmasındaki zorluğa dair yaptığı metodolojik uyarıdır[cite: 876, 921]."},
{soru: "<i>Kaynak A: \"Osmanlı ekonomisinin 'Büyük Ayrışma'daki konumu, çoğunlukla kurumsal esneklik eksikliği ve mülkiyet haklarının sınırlılığı perspektifinden tartışılmaktadır. Ancak bu açıklamanın tek başına yeterli olmadığı; Avrupa'nın sömürgeci kaynak akışlarının Osmanlı'nın içselci kurumsal açıklamasıyla tamamlanması gerektiği göz ardı edilmektedir.\"<br>Kaynak B: \"Teknolojik yaratıcılığın Avrupa'da sömürgeci dönemde yoğunlaşması rastlantısal değildir. Sömürge servetinin Avrupa'ya akması, bilim ve teknoloji kurumlarının finanse edilmesini; bu kurumların toplumsal meşruiyetinin artmasını ve entelektüel ağların güçlenmesini sağladı.\"</i><br><br><b>Pamuk ve Mokyr'ın bu iki tespitini sentezleyerek Osmanlı'nın Avrupa karşısında giderek açılan teknolojik ve ekonomik açığını açıklayan bütünleşik bir çerçeve oluşturunuz.</b>", secenekler: ["A) Pamuk ve Mokyr'ın tespitleri birbiriyle çelişmektedir.","B) Her iki tarihçi de Osmanlı'nın ekonomik gerilemeyi başarıyla tersine çevirdiğini göstermektedir.","C) Pamuk'un kurumsal açıklamanın sömürgeci kaynak akışlarıyla tamamlanması gerektiği tezi ile Mokyr'ın sömürge servetinin Avrupa'da teknoloji kurumlarını finanse ettiği saptaması birlikte okunduğunda, Osmanlı'nın açığı hem kurumsal kısıtları hem de sömürgeci kaynakların yarattığı Avrupa teknoloji kapasitesi avantajı çerçevesinde açıklamak gerekmektedir.","D) Mokyr, sömürge servetinin teknoloji gelişimine katkısını reddetmektedir.","E) Pamuk ve Mokyr'ın tespitleri Osmanlı'nın kurumsal yapısının değiştirilmesi durumunda tüm açığın kapanabileceğini kanıtlamaktadır."], cevap: "C) Pamuk'un kurumsal açıklamanın sömürgeci kaynak akışlarıyla tamamlanması gerektiği tezi ile Mokyr'ın sömürge servetinin Avrupa'da teknoloji kurumlarını finanse ettiği saptaması birlikte okunduğunda, Osmanlı'nın açığı hem kurumsal kısıtları hem de sömürgeci kaynakların yarattığı Avrupa teknoloji kapasitesi avantajı çerçevesinde açıklamak gerekmektedir.", aciklama: "Sentez, Osmanlı'daki iç kurumsal kısıtlar ile Avrupa'nın sömürge kaynaklı sermaye avantajını birleştirerek 'Büyük Ayrışma'yı daha bütünleşik bir zemine oturtur[cite: 885, 922]."},
{soru: "<i>Kaynak A: \"Osmanlı tarih yazımında 16. ve 17. yüzyıl gelişmelerinin sıklıkla 'çöküş' kavramı etrafında çerçevelenmesi, esas olarak dönemin Osmanlı tarihçilerinin kendi dönemlerini nasıl yorumladığını yansıtmaktadır. Bu özeleştirel anlatı, gerçek bir çöküşü tarif etmekten çok dönemin siyasi söyleminin ürettiği belirli bir toplumsal anlatı kalıbının dışavurumudur.\"<br>Kaynak B: \"16. yüzyıl Osmanlı tarihçileri, İbn Haldun'un döngüsel devlet teorisinden etkilenerek gözlemledikleri düzensizlikleri tarihsel zorunluluk kalıpları içinde yorumladı. Bu teorik çerçeve, onların dışsal ekonomik dönüşümlere —örneğin coğrafi keşiflerin yarattığı ticari kaymaya— ayrı ve özgül bir analitik kategori atfetmelerini engelledi.\"</i><br><br><b>Piterberg ve Fleischer'ın değerlendirmelerini birleştirerek Osmanlı tarih yazımının Avrupa sömürgeciliğini kavrama biçiminin sınırlılıklarını değerlendiren bütünleşik bir yorum çerçevesi oluşturunuz.</b>", secenekler: ["A) Piterberg ve Fleischer her ikisi de Osmanlı tarihçilerinin Avrupa sömürgeciliğini tam anlamıyla kavradığını ancak bunu kasıtlı olarak gizlediğini savunmaktadır.","B) Piterberg, Osmanlı tarih yazımının 'çöküş' anlatısının gerçek bir tarihsel analizi değil siyasi söylemin dışavurumu olduğunu ortaya koyarken; Fleischer, İbn Halduncu döngüsel çerçevenin coğrafi keşifler gibi dışsal dönüşümlere özgün analitik kategori tanımayı engellediğini göstermektedir. Her iki tespit bir araya geldiğinde Osmanlı tarih yazımının hem söylemsel hem de teorik düzeyde sömürgeciliği özgün bir olgu olarak kavrama kapasitesini kısıtladığı anlaşılmaktadır.","C) Fleischer, İbn Haldun'un teorisinin Osmanlı tarihçilerini coğrafi keşifleri doğru biçimde açıklamalarına yardımcı olduğunu göstermektedir.","D) Her iki tarihçi de Osmanlı tarih yazımının Avrupa sömürgeciliğini modern tarihçilerden çok daha iyi analiz ettiğini savunmaktadır.","E) Piterberg ve Fleischer'ın tespitleri birbiriyle çelişmektedir."], cevap: "B) Piterberg, Osmanlı tarih yazımının 'çöküş' anlatısının gerçek bir tarihsel analizi değil siyasi söylemin dışavurumu olduğunu ortaya koyarken; Fleischer, İbn Halduncu döngüsel çerçevenin coğrafi keşifler gibi dışsal dönüşümlere özgün analitik kategori tanımayı engellediğini göstermektedir. Her iki tespit bir araya geldiğinde Osmanlı tarih yazımının hem söylemsel hem de teorik düzeyde sömürgeciliği özgün bir olgu olarak kavrama kapasitesini kısıtladığı anlaşılmaktadır.", aciklama: "Bu bütünleşik yorum, Osmanlı aydınlarının dönemi algılama biçimlerinin (siyasi söylem ve İbn Halduncu şablonlar), sömürgecilik gibi dışsal ve yapısal süreçleri kavramsal olarak doğru tanımlamayı zorlaştırdığını gösterir[cite: 893, 923]."},
{soru: "<i>\"Osmanlı'nın Mısır'ı 1517'de fethetmesi, baharat ticaretinin denetimini ele geçirmek açısından büyük bir stratejik adımdı. Ancak bu fetih, Portekizlilerin Ümit Burnu güzergahını kullanmaya başlamasından yalnızca on dokuz yıl sonra gerçekleşti. Osmanlı, güzergahın kilit kavşaklarını ele geçirdiğinde, rakip güzergah halihazırda işler durumdaydı. Bu zamanlama, Osmanlı'nın baharat ticaretindeki aracılık rolünden elde ettiği kazanımları önemli ölçüde sınırladı.\"</i><br><br><b>Işıksal'ın bu analizine göre Osmanlı'nın Mısır'ı fethinin ticari stratejik değerini sınırlayan temel etken nedir?</b>", secenekler: ["A) Osmanlı'nın Mısır'ı askeri açıdan yeterince güçlü bir kuvvetle fethedememesi.","B) Mısır halkının Osmanlı yönetimine direnç göstermesi.","C) Portekiz'in Ümit Burnu güzergahını Osmanlı'nın Mısır fethinden önce zaten faaliyete geçirmiş olması.","D) Osmanlı'nın Mısır'dan elde ettiği gelirlerin tamamını askeri harcamalara aktarması.","E) Baharat ticaretinin Portekiz tarafından değil İspanya tarafından kontrol edilmesi."], cevap: "C) Portekiz'in Ümit Burnu güzergahını Osmanlı'nın Mısır fethinden önce zaten faaliyete geçirmiş olması.", aciklama: "Işıksal, Mısır fethinin stratejik başarısını 'zamanlama' faktörüne dayandırır; Portekiz'in rakip yolu 19 yıl önce açmış olması, Osmanlı'nın tekel kurma imkanını sınırlamıştır[cite: 965, 1136]."},
{soru: "<i>\"16. yüzyılda Osmanlı yönetiminin ticaret politikası, Avrupalı devletlerin izlediği sömürgeci modelden temel bir anlayış farkıyla ayrılıyordu: Osmanlı, ticareti bir devlet tekelinin kaynağı olarak değil, vergi ve gümrük geliri sağlayan bir faaliyetler bütünü olarak görüyordu. Bu anlayış, Osmanlı'nın farklı dinlerden ve milletlerden tüccara kapılarını açık tutmasını sağladı; ancak aynı zamanda merkezî bir ticaret şirketi kurma ve deniz aşırı ticaret ağları oluşturma yönünde kurumsal bir güdü de yaratmadı.\"</i><br><br><b>Akşin'in editörlüğünü yaptığı bu eserin değerlendirmesine göre Osmanlı'nın ticaret anlayışı ile Avrupalı sömürgeci modelin temel farkı nedir?</b>", secenekler: ["A) Osmanlı ticareti dini temellere, Avrupa ticareti ise bilimsel temellere dayandırmaktaydı.","B) Osmanlı, ticareti vergi geliri kaynağı olarak görürken Avrupa devleti tekelinde ticaret şirketleri kurarak deniz aşırı ağlar oluşturma yolunu seçmiştir.","C) Osmanlı, deniz aşırı ticaret ağları kurmuş; ancak bu ağları özel değil devlet eliyle yönetmiştir.","D) Avrupalı devletler ticaretten vergi almayı reddederken Osmanlı gümrük gelirine büyük önem vermekteydi.","E) Osmanlı ve Avrupa'nın ticaret anlayışı özünde aynıydı."], cevap: "B) Osmanlı, ticareti vergi geliri kaynağı olarak görürken Avrupa devleti tekelinde ticaret şirketleri kurarak deniz aşırı ağlar oluşturma yolunu seçmiştir.", aciklama: "Temel fark, Osmanlı'nın ticareti bir vergi toplama alanı olarak 'pasif' görmesi, Avrupa'nın ise devlet destekli şirketlerle 'aktif' bir sömürge ağını hedeflemesidir[cite: 973, 1137]."},
{soru: "<i>\"16. yüzyılın sonlarından itibaren Osmanlı'da ortaya çıkan 'levent' sorunu, kısmen ticaret yollarının kaymasıyla ortaya çıkan ekonomik çöküşün bir ürünüydü. Tımar düzeninin bozulmasıyla topraktan kopan köylüler ve geçimini yitirecek hâle gelen eski sipahiler, kentlere ya da eşkıya gruplarına katıldı. Bu toplumsal hareketlilik, Avrupa sömürgeciliğinin Osmanlı iç yapısında yarattığı dolaylı bir gerilimin somut yüzünü oluşturmaktaydı.\"</i><br><br><b>Cezar'ın bu değerlendirmesine göre Osmanlı'da görülen levent sorununun temel ekonomik arka planı nasıl açıklanabilir?</b>", secenekler: ["A) Leventler, Osmanlı'nın Avrupa sömürgecilerine karşı örgütlediği gizli bir direniş hareketiydi.","B) Tımar bozulması ve ticaret yollarının kaymasına bağlı ekonomik çöküş, topraksız kalan köylüleri ve eski sipahileri eşkıya gruplarına katılmaya itmiştir.","C) Levent sorunu yalnızca Osmanlı'nın Avrupa ile yaptığı savaşların yarattığı asker fazlasından kaynaklanmaktadır.","D) Osmanlı devleti, leventleri bilinçli olarak Avrupa tüccarlarına karşı kullanmak amacıyla oluşturmuştur.","E) Levent hareketleri, yalnızca Osmanlı'nın batı sınırlarında görülmüştür."], cevap: "B) Tımar bozulması ve ticaret yollarının kaymasına bağlı ekonomik çöküş, topraksız kalan köylüleri ve eski sipahileri eşkıya gruplarına katılmaya itmiştir.", aciklama: "Cezar'a göre levent sorunu, küresel ticaret yollarındaki değişimin (sömürgecilik) Osmanlı'nın toprak ve gelir sistemini bozarak yarattığı bir toplumsal sonuçtur[cite: 981, 1138]."},
{soru: "<i>\"Güneydoğu Asya liman kentleri, 15. yüzyılın sonlarında hem Müslüman hem de Çinli tüccarların yoğun katılımıyla canlı bir ticaret kozmopolisi oluşturuyordu. Portekizlilerin 1511'de Malakka'yı ele geçirmesi, bu ağı parçalamak yerine kısmen yeniden yönlendirdi: Müslüman tüccarlar, Portekiz kontrolündeki limanları devre dışı bırakarak alternatif güzergâhlar geliştirdi. Osmanlı İmparatorluğu bu güzergâhların arka planındaki siyasi destekçi konumuna yükseldi ve uzak coğrafyalardaki Müslüman ticaret ağlarını dolaylı olarak ayakta tutan bir güç işlevi gördü.\"</i><br><br><b>Reid'in bu tespitine göre Osmanlı'nın Güneydoğu Asya ticaret ağlarındaki rolü nasıl tanımlanabilir?</b>", secenekler: ["A) Osmanlı, Malakka'yı Portekizlilerden geri alarak Güneydoğu Asya'da doğrudan hâkimiyet kurmuştur.","B) Osmanlı, Güneydoğu Asya ticaretini tamamen engelleyerek Portekiz ile doğrudan çatışmaya girmiştir.","C) Osmanlı, Güneydoğu Asya'daki Müslüman ticaret ağlarının yeniden örgütlenmesinde dolaylı bir siyasi destek unsuru işlevi görmüştür.","D) Portekiz, Malakka'yı ele geçirerek Müslüman tüccarları tamamen çıkarmayı başarmıştır.","E) Osmanlı'nın Güneydoğu Asya'daki rolü, yalnızca elçilik faaliyetleriyle sınırlı kalmıştır."], cevap: "C) Osmanlı, Güneydoğu Asya'daki Müslüman ticaret ağlarının yeniden örgütlenmesinde dolaylı bir siyasi destek unsuru işlevi görmüştür.", aciklama: "Reid, Osmanlı'nın uzak Asya'daki ticaret ağlarını doğrudan yönetmekten ziyade, Portekiz'e direnen Müslüman tüccar ağlarının en büyük siyasi koruyucusu olduğunu belirtir[cite: 989, 1139]."},
{soru: "<i>\"Osmanlı'nın silah teknolojisi ve top dökümcülüğü, 16. yüzyılın ortalarına kadar Avrupa standartlarıyla karşılaştırılabilir bir düzeyde seyretmiştir. Ancak 17. yüzyıla gelindiğinde Osmanlı ile Avrupa arasındaki bu teknolojik denge belirgin biçimde Avrupa lehine bozuldu. Bu açığın temel nedeni, deniz aşırı sömürgeci faaliyetlerden elde edilen kaynakların Avrupa'da topçu teknolojisine yönelik ar-ge harcamalarını finanse etmesiydi; Osmanlı ise bu tür sürekli araştırma yatırımlarına yönelmede geç kaldı.\"</i><br><br><b>Ágoston'un bu değerlendirmesine göre Osmanlı ile Avrupa arasındaki 17. yüzyıl askeri teknoloji açığının temel nedeni nedir?</b>", secenekler: ["A) Osmanlı'nın 17. yüzyılda silah üretimini bilinçli olarak terk etmesi.","B) Sömürgeci faaliyetlerden elde edilen kaynakların Avrupa'da sürekli askeri teknoloji araştırmalarını finanse etmesi; Osmanlı'nın ise bu tür ar-ge yatırımlarına yönelmede geç kalması.","C) Osmanlı'nın 16. yüzyılda Avrupa silah teknolojisinin gerisinde kalması.","D) Avrupalı devletlerin Osmanlı'ya silah teknolojisi transferini engelleyen ambargo uygulaması.","E) Osmanlı'nın 17. yüzyılda kara ordusunu tamamen terk etmesi."], cevap: "B) Sömürgeci faaliyetlerden elde edilen kaynakların Avrupa'da sürekli askeri teknoloji araştırmalarını finanse etmesi; Osmanlı'nın ise bu tür ar-ge yatırımlarına yönelmede geç kalması.", aciklama: "Ágoston, askeri teknoloji açığının arkasında Avrupa'nın sömürge gelirlerini araştırma-geliştirme finansmanında kullanması, Osmanlı'nın ise bu mali kaynaklara ve yatırıma sahip olmamasının yattığını vurgular[cite: 997, 1140]."},
{soru: "<i>\"16. yüzyılın sonlarında ve 17. yüzyılın başlarında Anadolu kentlerinde hammadde fiyatları hızla yükselirken zanaat ürünlerinin fiyatları geride kalmaya başladı. Bu 'makas etkisi', küçük zanaatkârın üretim maliyetlerini karşılayamaz hâle gelmesine yol açtı. Söz konusu sürecin ardında, Amerika'dan gelen gümüşün Avrupa üzerinden aktığı enflasyonist dalga ile Avrupalı tekstil mallarının ucuz fiyatlarla Osmanlı pazarlarına girmesi yatıyordu.\"</i><br><br><b>Ergenç'in bu analizine göre Anadolu kent zanaatkârlarının 17. yüzyıl başlarında yaşadığı krizin temel ekonomik mekanizması nedir?</b>", secenekler: ["A) Anadolu zanaatkârları, Osmanlı devletinin vergi oranlarını artırması nedeniyle üretimden çekilmek zorunda kalmıştır.","B) Avrupa'dan gelen enflasyon ve ucuz tekstil mallarının yarattığı 'makas etkisi'; hammadde maliyetlerini artırırken ürün fiyatlarını geride bırakarak zanaatkârı mali çıkmaza sürüklemiştir.","C) Anadolu zanaatkârları, Osmanlı hükümeti tarafından Avrupa ürünlerini taklit etmeye zorlanmıştır.","D) Avrupalı tekstil mallarının Osmanlı pazarlarına girmesi, zanaatkârlara avantaj sağlamıştır.","E) Makas etkisi, yalnızca savaş dönemlerinde ortaya çıkan geçici bir fenomendi."], cevap: "B) Avrupa'dan gelen enflasyon ve ucuz tekstil mallarının yarattığı 'makas etkisi'; hammadde maliyetlerini artırırken ürün fiyatlarını geride bırakarak zanaatkârı mali çıkmaza sürüklemiştir.", aciklama: "Ergenç, dışsal enflasyon dalgası ile ucuz Avrupa mallarının, yerel zanaatkârın maliyet-satış dengesini (makas etkisi) bozarak onları krize sürüklediğini tespit eder[cite: 1006, 1141]."},
{soru: "<i>\"Osmanlı devlet aklı, 16. ve 17. yüzyıllarda dışsal ekonomik dönüşümleri kavramsal olarak yorumlarken kendine özgü bir çerçeve kullandı: Bozulma ve çöküş, 'örf'ten sapma ya da 'nizamın bozulması' olarak tanımlandı. Bu çerçeve, yapısal dönüşümleri ahlaki gerilemenin bir sonucu olarak okurken Avrupa sömürgeciliğinin yarattığı sistemik dışsal baskıyı kavramanın önüne geçti. Islahat talepleri ise ekseriyetle 'eski düzene dönüş' diliyle formüle edildi.\"</i><br><br><b>Mardin'in bu analizine göre Osmanlı siyasi düşüncesinin dönemin ekonomik dönüşümlerini kavramasının önünde duran temel zihinsel engel neydi?</b>", secenekler: ["A) Osmanlı siyasi düşünürlerinin yabancı dil bilgisinden yoksun olmaları.","B) Osmanlı reformcularının, Avrupalı devletlerin çıkarlarını kollamaya yönlendirilmesi.","C) Bozulma ve çöküşü 'örf'ten sapma şeklinde ahlaki kategorilerle okuyan geleneksel devlet düşüncesinin yapısal dışsal baskıları algılama kapasitesini kısıtlaması.","D) Osmanlı'nın Avrupa kaynaklı iktisat düşüncesini bilinçli olarak reddetmesi.","E) Osmanlı idarecilerinin ticaretin önemine hiç değer vermemesi."], cevap: "C) Bozulma ve çöküşü 'örf'ten sapma şeklinde ahlaki kategorilerle okuyan geleneksel devlet düşüncesinin yapısal dışsal baskıları algılama kapasitesini kısıtlaması.", aciklama: "Mardin, Osmanlı reform düşüncesinin sorunları 'ahlaki bir sapma' olarak çerçevelemesinin, modern küresel sömürgeci ekonominin yarattığı yapısal baskıları görmeyi engellediğini savunur[cite: 1015, 1142]."},
{soru: "<i>\"Portekiz'in Hint Okyanusu'ndaki hâkimiyet iddiası, pratikte hiçbir zaman tam bir tekele dönüşmedi. Koridor noktalarına yerleştirilen kaleler ve zorunlu pasaport sistemi (cartaz), ticaret üzerinde denetim kurmayı hedefliyordu; ancak geniş okyanus coğrafyasında bu denetimi sürdürmek hem personel hem de lojistik açıdan son derece maliyetliydi. Osmanlı ile Müslüman tüccarlar, zaman zaman açık çatışmaya girmeksizin bu denetim ağının boşluklarından faydalandı.\"</i><br><br><b>Crowley'nin bu değerlendirmesine göre Portekiz'in Hint Okyanusu'ndaki 'hâkimiyet' iddiasının temel sınırlılığı neydi?</b>", secenekler: ["A) Portekiz, Osmanlı'nın askeri üstünlüğü karşısında Hint Okyanusu'nu tamamen terk etti.","B) Portekiz'in cartaz sistemi başarılı bir ticaret tekeli kurdu.","C) Portekiz'in geniş okyanus coğrafyasında denetim ağı sürdürmenin yüksek maliyeti, tam bir ticaret tekeline ulaşmayı engelledi; Osmanlı ve Müslüman tüccarlar bu boşluklardan yararlandı.","D) Portekiz, cartaz sisteminden vazgeçerek serbest ticaret politikasına geçti.","E) Osmanlı, Portekiz'in kale sistemini fethedip yıktı."], cevap: "C) Portekiz'in geniş okyanus coğrafyasında denetim ağı sürdürmenin yüksek maliyeti, tam bir ticaret tekeline ulaşmayı engelledi; Osmanlı ve Müslüman tüccarlar bu boşluklardan yararlandı.", aciklama: "Portekiz hakimiyetinin coğrafi büyüklük ve maliyet nedeniyle sızdıran/eksik bir yapı arz etmesi, geleneksel ağların Portekiz tekelini aşmasını mümkün kılmıştır[cite: 1023, 1143]."},
{soru: "<i>\"Osmanlı yönetici sınıfının iktisadi düşüncesi, 'iaşeci' bir mantık üzerine kuruluydu: Mal bolluğunun sağlanması ve fiyat istikrarının korunması, ticaret kârının maksimize edilmesinden çok daha önemli bir devlet görevi sayılıyordu. Bu anlayış, tüccara potansiyel bir tedbir nesnesi olarak yaklaşır; onu sömürgeci bir güce dönüştürmeye değil, denetim altında tutmaya çalışırdı.\"</i><br><br><b>Issawi'nin bu analizine göre Osmanlı'nın iktisadi zihniyeti, Avrupalı sömürgeci güçlerin benimsediği ticaret anlayışından nasıl ayrılmaktadır?</b>", secenekler: ["A) Osmanlı, ticaret kârını her şeyin önünde tutarak sömürgeci genişlemeye destek vermiştir.","B) Osmanlı'nın iaşeci iktisadi zihniyeti, mal bolluğu ve fiyat istikrarını ön planda tutarken ticaret kârını maksimize etme ve tüccarı sömürgeci bir güce dönüştürme perspektifinden yoksundu.","C) Avrupalı devletler de Osmanlı gibi iaşeci bir iktisadi anlayış benimseyerek serbest piyasayı reddetti.","D) Osmanlı tüccarları, devlet baskısına rağmen Avrupa tüccarlarıyla eşit rekabet koşulları oluşturdu.","E) Osmanlı'nın iktisadi anlayışı, 18. yüzyılda tam anlamıyla Avrupalı sömürgeci modele dönüştü."], cevap: "B) Osmanlı'nın iaşeci iktisadi zihniyeti, mal bolluğu ve fiyat istikrarını ön planda tutarken ticaret kârını maksimize etme ve tüccarı sömürgeci bir güce dönüştürme perspektifinden yoksundu.", aciklama: "Issawi, Osmanlı iktisadi düşüncesinin merkeze tüketiciyi (bolluk) ve denetimi koyduğunu, Avrupa'nın aksine ticaretin sömürgeci bir büyüme aracı olarak kurgulanmadığını belirtir[cite: 1032, 1144]."},
{soru: "<i>\"Avrupa hegemonyasının kurulmasını salt Avrupa'nın içsel üstünlüğünün bir sonucu olarak okumak yanıltıcıdır. 14. ve 15. yüzyıllarda köklü Doğu ticaret ağlarının çöküşü — salgın hastalıklar, İlhanlı devletinin çözülmesi, Akdeniz ticaret dengelerinin sarsılması — Avrupa'nın yükselmesi için zemin hazırladı. Osmanlı bu kargaşa içinde topraklarını genişletirken, Avrupa aynı boşluğu denizaşırı yayılımla doldurdu.\"</i><br><br><b>Abu-Lughod'un bu çerçevesine göre Avrupa'nın deniz aşırı yayılımının başarıya ulaşmasında hangi bağlamsal etken belirleyici bir rol oynadı?</b>", secenekler: ["A) Avrupa'nın sağladığı içsel teknolojik üstünlük, yayılımın tek belirleyeni olmuştur.","B) Osmanlı'nın Avrupa'ya yönelik bilinçli ticaret engellemeleri, Avrupa'yı deniz aşırı yollara yöneltmiştir.","C) Doğu ticaret ağlarının salgın, siyasi çözülme ve denge sarsılmaları nedeniyle zayıflaması, Avrupa'nın deniz aşırı yayılımı için elverişli bir boşluk yarattı.","D) Avrupa, Osmanlı ile işbirliği yaparak ticaret yollarını birlikte yeniden düzenledi.","E) Abu-Lughod, Avrupa'nın yükselişini tamamen rastlantısal bir süreç olarak değerlendirmektedir."], cevap: "C) Doğu ticaret ağlarının salgın, siyasi çözülme ve denge sarsılmaları nedeniyle zayıflaması, Avrupa'nın deniz aşırı yayılımı için elverişli bir boşluk yarattı.", aciklama: "Abu-Lughod, Avrupa hegemonyasını salt bir 'başarı' olarak değil, Doğu'daki eski sistemlerin (İlhanlılar, salgınlar vb.) yarattığı boşluğu değerlendiren bir süreç olarak tanımlar[cite: 1040, 1145]."}
];
